"use client";
import { useCart } from "@/components/cart/cart-provider";
import { useState } from "react";
import { useRouter } from "next/navigation";
import { toast } from "sonner";
import { Trash2 } from "lucide-react";
import Link from "next/link";

export default function CartPage() {
  const router = useRouter();
  const { items, remove, setQty, subtotalCents, count } = useCart();
  const [busy, setBusy] = useState(false);

  async function checkout() {
    if (count === 0) return toast.error("Cart is empty");
    setBusy(true);
    const res = await fetch("/api/stripe/checkout", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ items: items.map(i => ({ id: i.id, quantity: i.quantity })), origin: window.location.origin }),
    });
    const j = await res.json();
    setBusy(false);
    if (!res.ok || !j.url) return toast.error(j.error || "Checkout failed");
    window.location.href = j.url;
  }

  return (
    <div className="mx-auto max-w-3xl px-6 py-12" data-testid="cart-page">
      <h1 className="font-display text-4xl font-medium">Your cart</h1>
      {items.length === 0 ? (
        <div className="mt-10 rounded-xl border border-dashed border-border p-10 text-center text-muted-foreground">
          Cart is empty. <Link href="/#supplements" className="underline">Browse supplements →</Link>
        </div>
      ) : (
        <>
          <ul className="mt-8 space-y-3" data-testid="cart-items">
            {items.map((i) => (
              <li key={i.id} className="vx-card flex items-center justify-between p-4">
                <div>
                  <p className="font-medium">{i.name}</p>
                  <p className="text-xs text-muted-foreground">${(i.priceCents/100).toFixed(2)} {i.recurring ? "/mo" : ""}</p>
                </div>
                <div className="flex items-center gap-3">
                  <input data-testid={`cart-qty-${i.id}`} type="number" min={1} value={i.quantity} onChange={(e) => setQty(i.id, Number(e.target.value))} className="w-16 rounded-md border border-border px-2 py-1 text-center text-sm" />
                  <button data-testid={`cart-remove-${i.id}`} onClick={() => remove(i.id)} className="rounded-full p-2 text-destructive hover:bg-destructive/10"><Trash2 size={14} /></button>
                </div>
              </li>
            ))}
          </ul>
          <div className="mt-8 flex items-center justify-between border-t border-border pt-6">
            <div>
              <p className="text-sm text-muted-foreground">Subtotal</p>
              <p data-testid="cart-subtotal" className="font-display text-3xl">${(subtotalCents/100).toFixed(2)}</p>
            </div>
            <button data-testid="cart-checkout-btn" onClick={checkout} disabled={busy} className="btn btn-primary">
              {busy ? "Redirecting…" : "Checkout →"}
            </button>
          </div>
        </>
      )}
    </div>
  );
}

import { ContactForm } from "@/components/public/contact-form";

export const metadata = {
  title: "Contact Us — VitalityX",
  description: "Get in touch with the VitalityX clinical team.",
};

export default function ContactPage() {
  return (
    <main className="min-h-screen pt-24 pb-24" data-testid="contact-page">
      <div className="mx-auto max-w-5xl px-6">
        <p className="text-xs uppercase tracking-widest text-muted-foreground">Get In Touch</p>
        <h1 className="mt-3 font-display text-4xl font-medium leading-tight md:text-5xl">
          Contact Our Clinical Team
        </h1>
        <p className="mt-4 max-w-xl text-muted-foreground">
          Have questions about our programs, your biological data, or a bespoke protocol? We're here to help.
        </p>

        <div className="mt-10 grid gap-10 md:grid-cols-2">
          <ContactForm />
          <div className="space-y-5">
            <h3 className="font-display text-xl">Contact Information</h3>
            <InfoBlock title="Email Support" lines={["care@vitalityx.health"]} />
            <InfoBlock title="Phone" lines={["+1 (800) 555-0199"]} />
            <InfoBlock title="Office Address" lines={["100 Precision Way, Suite 400", "San Francisco, CA 94105"]} />
            <InfoBlock title="Business Hours" lines={["Mon – Fri: 8:00 AM – 6:00 PM (PST)", "Sat – Sun: Clinical Support Only"]} />
            <p className="text-xs text-muted-foreground pt-4 border-t border-border">San Francisco HQ</p>
          </div>
        </div>
      </div>
    </main>
  );
}

function InfoBlock({ title, lines }: { title: string; lines: string[] }) {
  return (
    <div className="vx-card p-5 border border-border bg-card shadow-sm rounded-xl">
      <p className="text-xs uppercase tracking-widest text-[var(--vx-jade)] font-medium mb-2">{title}</p>
      {lines.map((l) => (
        <p key={l} className="mt-1 text-sm text-foreground">{l}</p>
      ))}
    </div>
  );
}

"use client";
import { useEffect, useState, Suspense } from "react";
import { useSearchParams } from "next/navigation";
import { useCart } from "@/components/cart/cart-provider";
import Link from "next/link";

function Confirmation() {
  const params = useSearchParams();
  const sessionId = params.get("session_id");
  const { clear } = useCart();
  const [order, setOrder] = useState<any>(null);
  const [tries, setTries] = useState(0);

  useEffect(() => {
    if (!sessionId) return;
    let cancelled = false;
    async function poll() {
      const res = await fetch(`/api/orders/by-session?session_id=${sessionId}`);
      const j = await res.json();
      if (cancelled) return;
      if (res.ok) {
        setOrder(j);
        if (j.status === "paid") clear();
        if (j.status !== "paid" && tries < 5) setTimeout(() => setTries((t) => t + 1), 2000);
      } else if (tries < 5) setTimeout(() => setTries((t) => t + 1), 2000);
    }
    poll();
    return () => { cancelled = true; };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [sessionId, tries]);

  return (
    <div className="mx-auto max-w-xl px-6 py-20 text-center" data-testid="order-confirmation">
      <div className="mx-auto flex h-16 w-16 items-center justify-center rounded-full bg-[var(--vx-jade)]/20 text-3xl">✓</div>
      <h1 className="mt-6 font-display text-4xl font-medium">Order confirmed</h1>
      <p className="mt-3 text-muted-foreground">Thanks for joining the stack. Your shipment will go out within 2 business days.</p>
      {order && (
        <div className="mt-8 rounded-xl border border-border bg-card p-6 text-left">
          <p className="text-xs uppercase tracking-widest text-muted-foreground">Order summary</p>
          <ul className="mt-3 space-y-2 text-sm">
            {(order.items || []).map((it: any, i: number) => (
              <li key={i} className="flex justify-between"><span>{it.name} × {it.quantity}</span><span>${((it.amount * it.quantity)/100).toFixed(2)}</span></li>
            ))}
          </ul>
          <div className="mt-4 flex justify-between border-t border-border pt-3 text-sm font-medium">
            <span>Total</span><span>${((order.amount_total || 0)/100).toFixed(2)}</span>
          </div>
          <p className="mt-3 text-xs text-muted-foreground">Status: <span className="badge badge-jade">{order.status}</span></p>
        </div>
      )}
      <Link href="/member/dashboard" className="btn btn-primary mt-8">Go to dashboard</Link>
    </div>
  );
}

export default function ConfirmationPage() {
  return <Suspense fallback={<div className="p-10 text-center">Loading…</div>}><Confirmation /></Suspense>;
}

