import { NextRequest, NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";
import { createNotification } from "@/lib/notifications";
import { logAudit } from "@/lib/audit";
import { CONSENT_VERSION } from "@/lib/consent";

export async function POST(req: NextRequest) {
  try {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

    const { data: consentRecord } = await supabase
      .from("consent_records")
      .select("consent_version")
      .eq("user_id", user.id)
      .eq("consent_version", CONSENT_VERSION)
      .single();

    if (!consentRecord) {
      return NextResponse.json({ error: "Forbidden: You must accept the latest Terms & Consent before proceeding." }, { status: 403 });
    }

    const { action, appointmentId, memberId, staffId } = await req.json();

    if (!action || !appointmentId) {
      return NextResponse.json({ error: "Missing required fields" }, { status: 400 });
    }

    // This is the backend hook for email placeholders (Booking confirmation, Reminder, Reschedule, Cancellation)
    // Here we simulate triggering a transactional email provider like Resend or SendGrid.

    let subject = "";
    if (action === "booked") subject = "Your VitalityX Session is Booked";
    if (action === "rescheduled") subject = "Your VitalityX Session has been Rescheduled";
    if (action === "cancelled") subject = "Your VitalityX Session was Cancelled";
    if (action === "confirmed") subject = "Your VitalityX Session is Confirmed";

    console.log(`[Email Placeholder] Action: ${action} | Subject: ${subject} | Appointment ID: ${appointmentId}`);

    if (action === "booked") {
      // Create notification for staff
      const { data: apt } = await supabase.from("appointments").select("staff_id").eq("id", appointmentId).single();
      if (apt?.staff_id) {
        await createNotification({
          userId: apt.staff_id,
          title: "New Appointment Booked",
          message: "A member has scheduled a new session.",
          type: "appointment_booked",
          category: "appointments",
          link: "/staff/sessions"
        });
      }
    }

    if (action === "rescheduled" || action === "cancelled") {
      // Notify both parties
      const { data: apt } = await supabase.from("appointments").select("staff_id, member_id").eq("id", appointmentId).single();
      if (apt) {
        const type = action === "cancelled" ? "appointment_cancelled" : "appointment_rescheduled";
        await createNotification({
          userId: apt.staff_id,
          title: `Appointment ${action === 'cancelled' ? 'Cancelled' : 'Rescheduled'}`,
          message: `An appointment was ${action}.`,
          type, category: "appointments", link: "/staff/sessions"
        });
        await createNotification({
          userId: apt.member_id,
          title: `Appointment ${action === 'cancelled' ? 'Cancelled' : 'Rescheduled'}`,
          message: `Your appointment was ${action}.`,
          type, category: "appointments", link: "/member/sessions"
        });
      }
    }

    return NextResponse.json({ success: true, message: `Hook for ${action} executed` });
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { triggerRecalculation } from "@/lib/biological-age";
import { createClient } from "@/lib/supabase/server";

export async function POST(req: Request) {
  try {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const body = await req.json();
    const targetMemberId = body.member_id || user.id;

    // Security: Only allow triggering for self unless admin/coach
    if (targetMemberId !== user.id) {
      const { data: profile } = await supabase.from('profiles').select('role').eq('id', user.id).single();
      if (!profile || (profile.role === 'Member')) {
        return NextResponse.json({ error: "Unauthorized" }, { status: 403 });
      }
    }

    const didUpdate = await triggerRecalculation(targetMemberId);

    return NextResponse.json({ success: true, updated: didUpdate });
  } catch (err: any) {
    console.error("Bio age trigger error:", err);
    return NextResponse.json({ error: err.message }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";
import { createNotification } from "@/lib/notifications";
import { logAudit } from "@/lib/audit";
import { CONSENT_VERSION, CONSENT_TEXT } from "@/lib/consent";

export async function GET(req: NextRequest) {
  try {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

    const { data, error } = await supabase
      .from("consent_records")
      .select("consent_version")
      .eq("user_id", user.id)
      .eq("consent_version", CONSENT_VERSION)
      .order("accepted_at", { ascending: false })
      .limit(1)
      .single();

    if (error && error.code !== 'PGRST116') {
      return NextResponse.json({ error: error.message }, { status: 500 });
    }

    return NextResponse.json({ hasConsented: !!data });
  } catch (error: unknown) {
    return NextResponse.json({ error: error instanceof Error ? error.message : "Unknown error" }, { status: 500 });
  }
}

export async function POST(req: NextRequest) {
  try {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

    const ipAddress = req.headers.get("x-forwarded-for") || req.headers.get("x-real-ip") || "unknown";
    const userAgent = req.headers.get("user-agent") || "unknown";

    const { error } = await supabase.from("consent_records").insert({
      user_id: user.id,
      consent_version: CONSENT_VERSION,
      consent_text: CONSENT_TEXT,
      ip_address: ipAddress,
      user_agent: userAgent
    });

    if (error) {
      console.error(error);
      return NextResponse.json({ error: "Failed to record consent" }, { status: 500 });
    }

    const { data: profile } = await supabase.from("profiles").select("role").eq("id", user.id).single();

    await logAudit({
      actorId: user.id,
      actorRole: profile?.role || "Member",
      action: "Consent accepted",
      resourceType: "consent",
      metadata: { consent_version: CONSENT_VERSION },
    });

    await createNotification({
      userId: user.id,
      title: "Consent Signed",
      message: `You have successfully signed version ${CONSENT_VERSION} of our consent forms.`,
      type: "consent_required",
      category: "consent",
      link: "/member/documents"
    });

    return NextResponse.json({ success: true, message: "Consent recorded" });
  } catch (error: unknown) {
    return NextResponse.json({ error: error instanceof Error ? error.message : "Unknown error" }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";

export async function POST(request: Request) {
  try {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const body = await request.json();

    if (body.action === "mark_all") {
      const { error } = await supabase
        .from("notifications")
        .update({ is_read: true, read_at: new Date().toISOString() })
        .eq("user_id", user.id)
        .eq("is_read", false);

      if (error) throw error;
      return NextResponse.json({ success: true });
    }

    if (body.action === "mark_one" && body.notificationId) {
      const { error } = await supabase
        .from("notifications")
        .update({ is_read: true, read_at: new Date().toISOString() })
        .eq("id", body.notificationId)
        .eq("user_id", user.id); // Security check

      if (error) throw error;
      return NextResponse.json({ success: true });
    }

    return NextResponse.json({ error: "Invalid action" }, { status: 400 });
  } catch (error: any) {
    console.error("[POST /api/notifications/read]", error);
    return NextResponse.json({ error: error.message || "Internal error" }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";
import { createNotification } from "@/lib/notifications";

export async function POST(request: Request) {
  try {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const body = await request.json();

    // Validate we have the required fields
    if (!body.userId || !body.title || !body.message || !body.type || !body.category) {
      return NextResponse.json({ error: "Missing required fields" }, { status: 400 });
    }

    // Call the server helper (which uses the Service Role key to bypass RLS)
    await createNotification({
      userId: body.userId,
      title: body.title,
      message: body.message,
      type: body.type,
      category: body.category,
      entityId: body.entityId,
      entityType: body.entityType,
      link: body.link,
      metadata: body.metadata,
    });

    return NextResponse.json({ success: true });
  } catch (error: any) {
    console.error("[POST /api/notifications/trigger]", error);
    return NextResponse.json({ error: error.message || "Internal error" }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from "next/server";
import Stripe from "stripe";
import { PRODUCTS } from "@/lib/products";
import { createClient } from "@/lib/supabase/server";
import { createAdminClient } from "@/lib/supabase/admin";
import { CONSENT_VERSION } from "@/lib/consent";

export async function POST(req: NextRequest) {
  try {
    const { items, origin } = (await req.json()) as { items: { id: string; quantity: number }[]; origin: string };
    if (!Array.isArray(items) || items.length === 0) return NextResponse.json({ error: "No items" }, { status: 400 });

    if (!process.env.STRIPE_SECRET_KEY) {
      return NextResponse.json({ error: "Checkout service unavailable" }, { status: 503 });
    }
    const stripe = new Stripe(process.env.STRIPE_SECRET_KEY);
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();

    // Enforce consent for authenticated users
    if (user) {
      const { data: consentRecord } = await supabase
        .from("consent_records")
        .select("consent_version")
        .eq("user_id", user.id)
        .eq("consent_version", CONSENT_VERSION)
        .single();

      if (!consentRecord) {
        return NextResponse.json({ error: "Forbidden: You must accept the latest Terms & Consent before proceeding." }, { status: 403 });
      }
    }

    // Build line_items from SERVER-SIDE catalog only
    const line_items = items
      .map((it) => {
        const p = PRODUCTS[it.id];
        if (!p) return null;
        return {
          price_data: {
            currency: "usd",
            product_data: { name: p.name, description: p.description },
            unit_amount: p.priceCents,
            ...(p.recurring ? { recurring: { interval: "month" as const } } : {}),
          },
          quantity: Math.max(1, Math.floor(it.quantity)),
        };
      })
      .filter((x): x is NonNullable<typeof x> => x !== null);

    if (line_items.length === 0) return NextResponse.json({ error: "Invalid items" }, { status: 400 });

    const hasRecurring = line_items.some((li) => li.price_data.recurring);
    const baseOrigin = origin || process.env.NEXT_PUBLIC_APP_URL || "";

    const session = await stripe.checkout.sessions.create({
      mode: hasRecurring ? "subscription" : "payment",
      line_items,
      success_url: `${baseOrigin}/order-confirmation?session_id={CHECKOUT_SESSION_ID}`,
      cancel_url: `${baseOrigin}/cart`,
      customer_email: user?.email,
      metadata: { member_id: user?.id || "guest" },
      ...(hasRecurring ? {} : { payment_method_types: ["card"] }),
    });

    // Insert pending order
    const admin = createAdminClient();
    await admin.from("orders").insert({
      member_id: user?.id || null,
      stripe_session_id: session.id,
      amount_total: line_items.reduce((s, li) => s + li.price_data.unit_amount * li.quantity, 0),
      currency: "usd",
      status: "pending",
      items: line_items.map((li) => ({ name: li.price_data.product_data.name, amount: li.price_data.unit_amount, quantity: li.quantity, recurring: !!li.price_data.recurring })),
    });

    return NextResponse.json({ url: session.url, session_id: session.id });
  } catch (e: any) {
    return NextResponse.json({ error: e?.message || "Internal error" }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from "next/server";
import Stripe from "stripe";
import { createClient } from "@/lib/supabase/server";
import { createAdminClient } from "@/lib/supabase/admin";

export async function POST(req: NextRequest) {
  try {
    const { subscription_id, stripe_subscription_id, status } = await req.json();
    if (!["paused", "cancelled"].includes(status)) return NextResponse.json({ error: "Invalid status" }, { status: 400 });

    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

    // Verify ownership via RLS-readable row
    const { data: row } = await supabase.from("supplement_subscriptions").select("*").eq("id", subscription_id).single();
    if (!row || row.member_id !== user.id) return NextResponse.json({ error: "Forbidden" }, { status: 403 });

    const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!);
    if (stripe_subscription_id) {
      if (status === "cancelled") {
        await stripe.subscriptions.cancel(stripe_subscription_id).catch((e) => console.warn("[stripe] cancel failed (mock?):", e.message));
      } else if (status === "paused") {
        await stripe.subscriptions.update(stripe_subscription_id, { pause_collection: { behavior: "void" } }).catch((e) => console.warn("[stripe] pause failed:", e.message));
      }
    }

    const admin = createAdminClient();
    await admin.from("supplement_subscriptions").update({ status }).eq("id", subscription_id);

    return NextResponse.json({ ok: true });
  } catch (e: any) {
    return NextResponse.json({ error: e?.message || "Internal" }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from "next/server";
import Stripe from "stripe";
import { createAdminClient } from "@/lib/supabase/admin";
import { sendEmail } from "@/lib/email";

export const runtime = "nodejs";

export async function POST(req: NextRequest) {
  const sig = req.headers.get("stripe-signature");
  const buf = Buffer.from(await req.arrayBuffer());
  const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!);
  const secret = process.env.STRIPE_WEBHOOK_SECRET || "";

  let event: Stripe.Event;
  try {
    if (secret && sig) {
      event = stripe.webhooks.constructEvent(buf, sig, secret);
    } else {
      // Dev/preview: trust body without signature verification
      event = JSON.parse(buf.toString()) as Stripe.Event;
      console.warn("[webhook] STRIPE_WEBHOOK_SECRET not configured — skipping signature verification");
    }
  } catch (err: any) {
    console.error("[webhook] signature failure", err.message);
    return NextResponse.json({ error: "Bad signature" }, { status: 400 });
  }

  const admin = createAdminClient();

  if (event.type === "checkout.session.completed") {
    const session = event.data.object as Stripe.Checkout.Session;
    const member_id = session.metadata?.member_id !== "guest" ? session.metadata?.member_id : null;

    // Mark order paid
    const { data: order } = await admin
      .from("orders")
      .update({ status: "paid", amount_total: session.amount_total || 0 })
      .eq("stripe_session_id", session.id)
      .select()
      .single();

    // Recurring → create subscription rows
    if (session.mode === "subscription" && session.subscription && member_id) {
      const sub = await stripe.subscriptions.retrieve(session.subscription as string, { expand: ["items.data.price.product"] });
      for (const it of sub.items.data) {
        const product = it.price.product as Stripe.Product;
        await admin.from("supplement_subscriptions").insert({
          member_id,
          stripe_subscription_id: sub.id,
          product_name: product.name,
          status: "active",
        });
      }
    }

    // Confirmation email
    if (session.customer_email) {
      const itemsList = (order?.items || []).map((i: any) => `<li>${i.name} × ${i.quantity}</li>`).join("");
      await sendEmail({
        to: session.customer_email,
        subject: "Your VitalityX order is confirmed",
        html: `<div style="font-family:Georgia,serif;color:#1a1a2e">
          <h2>Order confirmed</h2>
          <p>Thanks for joining the stack. Your shipment will go out within 2 business days.</p>
          <ul>${itemsList}</ul>
          <p style="margin-top:24px">Total: <strong>$${((session.amount_total || 0)/100).toFixed(2)}</strong></p>
        </div>`,
      });
    }
  }

  return NextResponse.json({ received: true });
}

