            <Link href="/member/sessions" className="btn btn-jade text-xs"><Calendar size={14} /> Book</Link>
          </div>
        </div>
      </div>

      <div className="mt-6 grid gap-6 lg:grid-cols-3">
        {/* Bio age trend */}
        <div data-testid="bio-age-chart" className="vx-card p-6 lg:col-span-2">
