"use client";
import { useEffect, useState, useRef } from "react";
import { createClient } from "@/lib/supabase/client";
import { getInitials } from "@/lib/utils";
import { toast } from "sonner";

const supabase = createClient();
type Msg = { id: string; sender_id: string; receiver_id: string; content: string; created_at: string };

export default function MessagesPage() {
  const [me, setMe] = useState<string | null>(null);
  const [assignedCoachId, setAssignedCoachId] = useState<string | null>(null);
  const [partners, setPartners] = useState<any[]>([]);
  const [selectedPartner, setSelectedPartner] = useState<any | null>(null);
  const [messages, setMessages] = useState<Msg[]>([]);
  const [text, setText] = useState("");
  const [lastReadTimestamps, setLastReadTimestamps] = useState<Record<string, string>>({});
  const endRef = useRef<HTMLDivElement>(null);

  async function loadAll() {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;
    setMe(user.id);

    // Fetch assigned coach
    const { data: cr } = await supabase
      .from("client_records")
      .select("assigned_coach_id")
      .eq("member_id", user.id)
      .single();
    const coachId = cr?.assigned_coach_id || null;
    setAssignedCoachId(coachId);

    // Fetch all messages involving user
    const { data: allMsgs } = await supabase
      .from("messages")
      .select("*")
      .or(`sender_id.eq.${user.id},receiver_id.eq.${user.id}`)
      .order("created_at");

    const msgs = allMsgs || [];
    setMessages(msgs);

    // Find all partner IDs
    const partnerIds = new Set<string>();
    if (coachId) partnerIds.add(coachId);
    msgs.forEach((m) => {
      if (m.sender_id !== user.id) partnerIds.add(m.sender_id);
      if (m.receiver_id !== user.id) partnerIds.add(m.receiver_id);
    });

    if (partnerIds.size > 0) {
      // Fetch profiles of all these partners
      const { data: profiles } = await supabase
        .from("profiles")
        .select("id, full_name, role, email")
        .in("id", Array.from(partnerIds));

      const loadedPartners = profiles || [];
      setPartners(loadedPartners);

      // Default to opening assigned coach thread on load (or first, preserving current selection)
      setSelectedPartner((current: any) => {
        if (current) {
          const updated = loadedPartners.find((p) => p.id === current.id);
          return updated || current;
        }
        if (coachId) {
          return loadedPartners.find((p) => p.id === coachId) || loadedPartners[0] || null;
        }
        return loadedPartners[0] || null;
      });
    }
  }

  useEffect(() => {
    const saved = localStorage.getItem("vx_last_read_timestamps");
    if (saved) {
      try {
        setLastReadTimestamps(JSON.parse(saved));
      } catch (e) {
        console.warn(e);
      }
    }
  }, []);

  useEffect(() => {
    loadAll();

    const channel = supabase.channel("messages-all")
      .on("postgres_changes", { event: "INSERT", schema: "public", table: "messages" }, (payload) => {
        const m = payload.new as Msg;
        setMe((currentMe) => {
          if (!currentMe) return currentMe;
          if (m.sender_id === currentMe || m.receiver_id === currentMe) {
            setMessages((prev) => {
              if (prev.find((x) => x.id === m.id)) return prev;
              return [...prev, m];
            });
            loadAll();
          }
          return currentMe;
        });
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, []);

  useEffect(() => {
    if (selectedPartner) {
      const nowStr = new Date().toISOString();
      setLastReadTimestamps((prev) => {
        const next = { ...prev, [selectedPartner.id]: nowStr };
        localStorage.setItem("vx_last_read_timestamps", JSON.stringify(next));
        return next;
      });
    }
  }, [selectedPartner, messages]);

  useEffect(() => {
    endRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, selectedPartner]);

  async function send() {
    if (!text.trim() || !me || !selectedPartner) return;
    const { error, data } = await supabase.from("messages").insert({
      sender_id: me,
      receiver_id: selectedPartner.id,
      content: text.trim()
    }).select().single();
    if (error) return toast.error(error.message);
    setText("");
    if (data) {
      setMessages((prev) => prev.find((x) => x.id === data.id) ? prev : [...prev, data as Msg]);
    }
  }

  // Map partners with details
  const enrichedPartners = partners.map((p) => {
    const thread = messages.filter(
      (m) =>
        (m.sender_id === me && m.receiver_id === p.id) ||
        (m.sender_id === p.id && m.receiver_id === me)
    );
    const lastMsg = thread[thread.length - 1];
    const lastRead = lastReadTimestamps[p.id] || "1970-01-01T00:00:00.000Z";
    const unreadCount = thread.filter(
      (m) =>
        m.sender_id === p.id &&
        new Date(m.created_at) > new Date(lastRead)
    ).length;

    return {
      ...p,
      lastMessageContent: lastMsg ? lastMsg.content : "No messages yet",
      unreadCount,
    };
  });

  const selectedThreadMessages = selectedPartner
    ? messages.filter(
        (m) =>
          (m.sender_id === me && m.receiver_id === selectedPartner.id) ||
          (m.sender_id === selectedPartner.id && m.receiver_id === me)
      )
    : [];

  return (
    <div className="mx-auto flex h-[calc(100vh-4rem)] max-w-5xl gap-6 px-6 py-6" data-testid="member-messages-page">
      {/* Left panel: thread list */}
      <div className="w-80 shrink-0 border-r border-border pr-4 flex flex-col h-full overflow-y-auto">
        <h2 className="font-display text-xl mb-4">Conversations</h2>
        <div className="space-y-1.5 flex-1">
          {enrichedPartners.map((p) => {
            const isActive = selectedPartner?.id === p.id;
            return (
              <button
                key={p.id}
                onClick={() => setSelectedPartner(p)}
                className={`w-full flex items-center gap-3 rounded-xl p-3 text-left transition ${
                  isActive ? "bg-muted border border-border" : "hover:bg-muted/50 border border-transparent"
                }`}
              >
                <span className="flex h-10 w-10 shrink-0 items-center justify-center rounded-full bg-[var(--vx-ink)] text-sm font-semibold text-white">
                  {getInitials(p.full_name || p.email)}
                </span>
                <div className="min-w-0 flex-1">
                  <div className="flex justify-between items-baseline">
                    <p className="font-medium text-sm truncate">{p.full_name || "Staff"}</p>
                    <span className="text-[10px] text-muted-foreground uppercase tracking-wider">{p.role}</span>
                  </div>
                  <p className="text-xs text-muted-foreground truncate mt-0.5">{p.lastMessageContent}</p>
                </div>
                {p.unreadCount > 0 && (
                  <span className="flex h-5 min-w-[20px] items-center justify-center rounded-full bg-destructive px-1 text-[10px] font-semibold text-white shrink-0">
                    {p.unreadCount}
                  </span>
                )}
              </button>
            );
          })}
          {enrichedPartners.length === 0 && (
            <p className="text-sm text-muted-foreground">No conversations yet.</p>
          )}
        </div>
      </div>

      {/* Right panel: current thread */}
      <div className="flex-1 flex flex-col h-full">
        {selectedPartner ? (
          <>
            <div className="border-b border-border pb-4 flex justify-between items-center">
              <div>
                <h1 className="font-display text-2xl">{selectedPartner.full_name || "Staff"}</h1>
                <p className="text-xs text-muted-foreground uppercase tracking-wider mt-0.5">{selectedPartner.role}</p>
              </div>
            </div>
            {/* Messages list */}
            <div className="flex-1 overflow-y-auto py-4 space-y-2" data-testid="messages-list">
              {selectedThreadMessages.length === 0 ? (
                <p className="text-center text-sm text-muted-foreground py-8">No messages yet. Say hi 👋</p>
              ) : (
                selectedThreadMessages.map((m) => {
                  const isMe = m.sender_id === me;
                  return (
                    <div key={m.id} className={`flex ${isMe ? "justify-end" : "justify-start"}`}>
                      <div className={`max-w-[75%] rounded-2xl px-4 py-2 text-sm ${isMe ? "bg-[var(--vx-ink)] text-white" : "bg-card border border-border"}`}>
                        {m.content}
                      </div>
                    </div>
                  );
                })
              )}
              <div ref={endRef} />
            </div>
            {/* Input box */}
            <div className="flex gap-2 border-t border-border pt-4">
              <input
                data-testid="message-input"
                value={text}
                onChange={(e) => setText(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && send()}
                placeholder="Type a message…"
                className="vx-input flex-1"
              />
              <button data-testid="message-send" onClick={send} className="btn btn-primary">Send</button>
            </div>
          </>
        ) : (
          <div className="flex-1 flex items-center justify-center text-muted-foreground text-sm">
            Select a conversation to start messaging
          </div>
        )}
      </div>
    </div>
  );
}

"use client";
import useSWR from "swr";
import { useState } from "react";
import { createClient } from "@/lib/supabase/client";
import { CheckCircle2, Circle, ChevronDown } from "lucide-react";
import { toast } from "sonner";

const supabase = createClient();

export default function ProtocolPage() {
  const [openId, setOpenId] = useState<string | null>(null);
  const { data, mutate } = useSWR("protocol-full", async () => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return null;
    const [{ data: items }, { data: comps }] = await Promise.all([
      supabase.from("protocol_items").select("*").eq("member_id", user.id).eq("active", true).order("created_at"),
      supabase.from("protocol_completions").select("item_id, completed_at").eq("member_id", user.id).gte("completed_at", new Date(new Date().toDateString()).toISOString()),
    ]);
    return { userId: user.id, items: items || [], doneToday: new Set((comps || []).map((c: any) => c.item_id)) };
  });
  if (!data) return <p className="p-8 text-sm text-muted-foreground">Loading…</p>;

  async function toggle(id: string) {
    if (!data) return;
    if (data.doneToday.has(id)) {
      await supabase.from("protocol_completions").delete().eq("item_id", id).eq("member_id", data.userId)
        .gte("completed_at", new Date(new Date().toDateString()).toISOString());
    } else {
      const { error } = await supabase.from("protocol_completions").insert({ item_id: id, member_id: data.userId });
      if (error) toast.error(error.message);
    }
    mutate();
  }

  return (
    <div className="mx-auto max-w-3xl px-6 py-10" data-testid="member-protocol-page">
      <h1 className="font-display text-4xl font-medium">Protocol</h1>
      <p className="mt-2 text-muted-foreground">Tap to mark complete. Tap the chevron to read the reasoning.</p>
      {data.items.length === 0 ? (
        <p className="mt-8 rounded-lg border border-dashed p-8 text-center text-sm text-muted-foreground">Your coach hasn&apos;t published items yet.</p>
      ) : (
        <ul className="mt-8 space-y-3">
          {data.items.map((it: any) => {
            const done = data.doneToday.has(it.id);
            const open = openId === it.id;
            return (
              <li key={it.id} className="vx-card">
                <div className="flex items-center gap-3 p-4">
                  <button data-testid={`protocol-check-${it.id}`} onClick={() => toggle(it.id)}>
                    {done ? <CheckCircle2 size={20} className="text-[var(--vx-jade)]" /> : <Circle size={20} className="text-muted-foreground" />}
                  </button>
                  <span className={`flex-1 ${done ? "line-through opacity-60" : ""}`}>{it.title}</span>
                  <button onClick={() => setOpenId(open ? null : it.id)} className="rounded-full p-1 hover:bg-muted">
                    <ChevronDown size={16} className={`transition ${open ? "rotate-180" : ""}`} />
                  </button>
                </div>
                {open && <p className="border-t border-border px-4 py-3 text-sm text-muted-foreground">{it.why_text || "No reasoning provided yet."}</p>}
              </li>
            );
          })}
        </ul>
      )}
    </div>
  );
}

"use client";
import useSWR from "swr";
import { useState } from "react";
import { createClient } from "@/lib/supabase/client";
import { formatDateTime } from "@/lib/utils";
import { toast } from "sonner";
import { BookingModal } from "@/components/portal/BookingModal";
import { RescheduleModal } from "@/components/portal/RescheduleModal";
import { Video, MapPin, Clock, FileText } from "lucide-react";
import { logClientAudit } from "@/lib/audit-client";
import { format } from "date-fns";

const supabase = createClient();

export default function SessionsPage() {
  const [showBookingModal, setShowBookingModal] = useState(false);
  const [rescheduleAppointment, setRescheduleAppointment] = useState<Record<string, any> | null>(null);

  const { data, mutate } = useSWR("appointments", async () => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return null;
    const { data: cr } = await supabase.from("client_records").select("assigned_coach_id").eq("member_id", user.id).single();
    const { data: appointments } = await supabase
      .from("appointments")
      .select("*, coach:profiles!appointments_staff_id_fkey(full_name)")
      .eq("member_id", user.id)
      .order("scheduled_start", { ascending: true });

    return { userId: user.id, coachId: cr?.assigned_coach_id, appointments: appointments || [] };
  });

  if (!data) return <p className="p-8 text-sm text-muted-foreground">Loading…</p>;

  const upcoming = data.appointments.filter((s: Record<string, any>) => 
    new Date(s.scheduled_start) >= new Date() && s.status !== "Cancelled" && s.status !== "Completed"
  );

  const past = data.appointments.filter((s: Record<string, any>) => 
    new Date(s.scheduled_start) < new Date() || s.status === "Cancelled" || s.status === "Completed"
  ).sort((a: Record<string, any>, b: Record<string, any>) => new Date(b.scheduled_start).getTime() - new Date(a.scheduled_start).getTime());

  async function book(bookingData: Record<string, any>) {
    const { error, data: newApt } = await supabase.from("appointments").insert({
      member_id: data!.userId,
      staff_id: bookingData.staff_id,
      title: bookingData.title,
      session_type: bookingData.session_type,
      scheduled_start: bookingData.scheduled_start,
      scheduled_end: bookingData.scheduled_end,
      status: "Scheduled",
    }).select().single();

    if (error) return toast.error(error.message);

    fetch("/api/appointments", { method: "POST", body: JSON.stringify({ action: "booked", appointmentId: newApt.id }) });

    await logClientAudit("Appointment created", {
      resourceType: "appointment",
      resourceId: newApt.id,
      metadata: { service: bookingData.session_type, scheduled_at: bookingData.scheduled_start, staff_id: bookingData.staff_id }
    });

    toast.success("Session booked successfully.");
    setShowBookingModal(false);
    mutate();
  }

  async function cancelAppointment(id: string) {
    const { error } = await supabase
      .from("appointments")
      .update({ status: "Cancelled", updated_at: new Date().toISOString() })
      .eq("id", id);
    if (error) return toast.error(error.message);

    fetch("/api/appointments", { method: "POST", body: JSON.stringify({ action: "cancelled", appointmentId: id }) });

    await logClientAudit("Appointment cancelled", {
      resourceType: "appointment",
      resourceId: id
    });

    toast.success("Session cancelled.");
    mutate();
  }

  async function reschedule(newStart: string, newEnd: string) {
    if (!rescheduleAppointment) return;
    const { error } = await supabase
      .from("appointments")
      .update({ 
        scheduled_start: newStart,
        scheduled_end: newEnd,
        status: "Rescheduled",
        updated_at: new Date().toISOString() 
      })
      .eq("id", rescheduleAppointment.id);

    if (error) return toast.error(error.message);

    fetch("/api/appointments", { method: "POST", body: JSON.stringify({ action: "rescheduled", appointmentId: rescheduleAppointment.id }) });

    await logClientAudit("Appointment rescheduled", {
      resourceType: "appointment",
      resourceId: rescheduleAppointment.id,
      metadata: { new_scheduled_at: newStart }
    });

    toast.success("Session rescheduled.");
    setRescheduleAppointment(null);
    mutate();
  }

  return (
    <div className="mx-auto max-w-4xl px-6 py-10" data-testid="member-sessions-page">
      <div className="flex items-center justify-between">
        <h1 className="font-display text-4xl font-medium">Sessions</h1>
        <button onClick={() => setShowBookingModal(true)} className="btn btn-primary">+ Book Session</button>
      </div>

      <h2 className="mt-10 font-display text-xl">Upcoming</h2>
      {upcoming.length === 0 ? <p className="mt-3 text-sm text-muted-foreground">No upcoming sessions. Book one to stay on track.</p> :
        <div className="mt-4 grid gap-4">{upcoming.map((s: Record<string, any>) => (
          <AppointmentCard 
            key={s.id} 
            appointment={s} 
            onReschedule={() => setRescheduleAppointment(s)} 
            onCancel={() => cancelAppointment(s.id)}
          />
        ))}</div>
      }

      <h2 className="mt-12 font-display text-xl">Past & Cancelled</h2>
      {past.length === 0 ? <p className="mt-3 text-sm text-muted-foreground">No past sessions.</p> :
        <div className="mt-4 grid gap-4 opacity-75">{past.map((s: Record<string, any>) => (
          <AppointmentCard key={s.id} appointment={s} readOnly />
        ))}</div>
      }

      {showBookingModal && (
        <BookingModal 
          preselectedCoachId={data.coachId}
          onClose={() => setShowBookingModal(false)} 
          onBook={book} 
        />
      )}
      {rescheduleAppointment && (
        <RescheduleModal
          currentScheduledAt={rescheduleAppointment.scheduled_start}
          onClose={() => setRescheduleAppointment(null)}
          onReschedule={reschedule}
        />
      )}
    </div>
  );
}

function AppointmentCard({ appointment, onReschedule, onCancel, readOnly }: { appointment: Record<string, any>, onReschedule?: () => void, onCancel?: () => void, readOnly?: boolean }) {
  const isPast = new Date(appointment.scheduled_start) < new Date();

  return (
    <div className="vx-card p-5">
      <div className="flex flex-col md:flex-row justify-between md:items-start gap-4">
        <div>
          <div className="flex items-center gap-3">
            <h3 className="font-display text-lg">{appointment.title}</h3>
            <span className={`badge ${
              appointment.status === 'Cancelled' ? 'badge-coral' : 
              appointment.status === 'Confirmed' ? 'badge-jade' : 
              'badge-ink'
            }`}>{appointment.status}</span>
          </div>

          <div className="mt-3 grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-2 text-sm text-muted-foreground">
            <div className="flex items-center gap-2">
              <Clock size={16} />
              <span>{format(new Date(appointment.scheduled_start), "MMM d, yyyy")} • {format(new Date(appointment.scheduled_start), "h:mm a")}</span>
            </div>

            {appointment.coach && (
              <div className="flex items-center gap-2">
                <FileText size={16} />
                <span>Coach: {appointment.coach.full_name}</span>
              </div>
            )}

            {appointment.location && (
              <div className="flex items-center gap-2">
                <MapPin size={16} />
                <span>{appointment.location}</span>
              </div>
            )}
          </div>
        </div>

        {!readOnly && (
          <div className="flex flex-col sm:flex-row gap-2 shrink-0">
            {appointment.meeting_link && !isPast && appointment.status !== 'Cancelled' && (
              <a href={appointment.meeting_link} target="_blank" rel="noreferrer" className="btn bg-[var(--vx-jade)] text-black hover:bg-[var(--vx-jade)]/90 px-4 py-2 text-sm flex items-center justify-center gap-2">
                <Video size={16} /> Join
              </a>
            )}

            <div className="flex gap-2">
              <button onClick={onReschedule} className="btn btn-outline px-3 py-2 text-sm flex-1 sm:flex-none">Reschedule</button>
              <button onClick={onCancel} className="btn btn-ghost text-destructive hover:bg-destructive/10 px-3 py-2 text-sm flex-1 sm:flex-none">Cancel</button>
            </div>
          </div>
        )}

        {readOnly && appointment.status !== 'Cancelled' && appointment.notes && (
          <div className="w-full mt-2 rounded-lg bg-white/5 p-3 text-sm">
            <span className="font-medium text-foreground block mb-1">Coach Notes:</span>
            {appointment.notes}
          </div>
        )}
      </div>
    </div>
  );
}

"use client";
import { useEffect, useState } from "react";
import { createClient } from "@/lib/supabase/client";
import { toast } from "sonner";

const supabase = createClient();

export default function SettingsPage() {
  const [profile, setProfile] = useState<any>(null);
  const [email, setEmail] = useState("");
  const [newPwd, setNewPwd] = useState("");

  useEffect(() => {
    (async () => {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;
      setEmail(user.email || "");
      const { data } = await supabase.from("profiles").select("*").eq("id", user.id).single();
      setProfile(data);
    })();
  }, []);

  async function saveProfile(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault();
    const f = new FormData(e.currentTarget);
    const full_name = f.get("full_name") as string;
    const { error } = await supabase.from("profiles").update({
      full_name,
      notification_prefs: {
        email_protocol_changes: f.get("email_protocol_changes") === "on",
        email_session_reminders: f.get("email_session_reminders") === "on",
      },
    }).eq("id", profile.id);
    if (error) return toast.error(error.message);
    toast.success("Profile saved");
  }

  async function changeEmail() {
    const { error } = await supabase.auth.updateUser({ email });
    if (error) return toast.error(error.message);
    toast.success("Confirmation sent to new email.");
  }
  async function changePassword() {
    if (newPwd.length < 8) return toast.error("Password too short");
    const { error } = await supabase.auth.updateUser({ password: newPwd });
    if (error) return toast.error(error.message);
    toast.success("Password updated");
    setNewPwd("");
  }

  if (!profile) return <p className="p-8 text-sm text-muted-foreground">Loading…</p>;

  return (
    <div className="mx-auto max-w-2xl px-6 py-10" data-testid="member-settings-page">
      <h1 className="font-display text-4xl font-medium">Settings</h1>

      <form onSubmit={saveProfile} className="mt-8 vx-card p-6 space-y-4">
        <h2 className="font-display text-xl">Profile</h2>
        <input data-testid="settings-name" name="full_name" defaultValue={profile.full_name} className="vx-input" placeholder="Full name" />
        <div className="space-y-2 text-sm">
          <label className="flex gap-2"><input type="checkbox" name="email_protocol_changes" defaultChecked={profile.notification_prefs?.email_protocol_changes} /> Email me on protocol changes</label>
          <label className="flex gap-2"><input type="checkbox" name="email_session_reminders" defaultChecked={profile.notification_prefs?.email_session_reminders} /> Email me 24h before sessions</label>
        </div>
        <button data-testid="settings-save" className="btn btn-primary">Save</button>
      </form>

      <div className="mt-6 vx-card p-6 space-y-3">
        <h2 className="font-display text-xl">Email</h2>
        <input data-testid="settings-email" value={email} onChange={(e) => setEmail(e.target.value)} type="email" className="vx-input" />
        <button onClick={changeEmail} className="btn btn-outline">Change email</button>
      </div>

      <div className="mt-6 vx-card p-6 space-y-3">
        <h2 className="font-display text-xl">Password</h2>
        <input data-testid="settings-password" value={newPwd} onChange={(e) => setNewPwd(e.target.value)} type="password" className="vx-input" placeholder="New password" />
        <button onClick={changePassword} className="btn btn-outline">Update password</button>
      </div>
    </div>
  );
}

"use client";
import useSWR from "swr";
import { createClient } from "@/lib/supabase/client";
import Link from "next/link";
import { toast } from "sonner";

const supabase = createClient();

export default function SupplementsPage() {
  const { data, mutate } = useSWR("supplements", async () => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return null;
    const { data: subs } = await supabase.from("supplement_subscriptions").select("*").eq("member_id", user.id).order("created_at", { ascending: false });
    return { userId: user.id, subs: subs || [] };
  });

  async function setStatus(id: string, stripe_id: string, status: "paused" | "cancelled") {
    const res = await fetch("/api/stripe/subscription", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ subscription_id: id, stripe_subscription_id: stripe_id, status }),
    });
    if (!res.ok) {
      const j = await res.json().catch(() => ({}));
      return toast.error(j.error || "Action failed");
    }
    toast.success(`Subscription ${status}`);
    mutate();
  }

  if (!data) return <p className="p-8 text-sm text-muted-foreground">Loading…</p>;

  return (
    <div className="mx-auto max-w-3xl px-6 py-10" data-testid="member-supplements-page">
      <h1 className="font-display text-4xl font-medium">Supplements</h1>
      <p className="mt-2 text-muted-foreground">Manage your active subscriptions.</p>

      {data.subs.length === 0 ? (
        <div className="mt-10 rounded-xl border border-dashed border-border p-8 text-center text-sm text-muted-foreground">
          No active subscriptions. <Link href="/#supplements" className="underline">Browse the stack →</Link>
        </div>
      ) : (
        <ul className="mt-8 space-y-3">
          {data.subs.map((s: any) => (
            <li key={s.id} className="vx-card flex items-center justify-between p-5">
              <div>
                <p className="font-medium">{s.product_name}</p>
                <p className="text-xs text-muted-foreground">Status: <span className={`badge ${s.status==="active"?"badge-jade":s.status==="paused"?"badge-amber":"badge-coral"}`}>{s.status}</span></p>
              </div>
              <div className="flex gap-2">
                {s.status === "active" && <button data-testid={`pause-${s.id}`} onClick={() => setStatus(s.id, s.stripe_subscription_id, "paused")} className="btn btn-outline text-xs">Pause</button>}
                {s.status === "paused" && <button data-testid={`resume-${s.id}`} onClick={() => setStatus(s.id, s.stripe_subscription_id, "paused")} className="btn btn-outline text-xs">Resume</button>}
                {s.status !== "cancelled" && <button data-testid={`cancel-${s.id}`} onClick={() => setStatus(s.id, s.stripe_subscription_id, "cancelled")} className="btn btn-outline text-xs">Cancel</button>}
              </div>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

"use client";

import { useState } from "react";
import useSWR from "swr";
import { useRouter } from "next/navigation";
import Image from "next/image";
import { createClient } from "@/lib/supabase/client";
import { StaffProfileModal } from "@/components/member/StaffProfileModal";
import { BookingModal } from "@/components/portal/BookingModal";
import { MessageCircle, Calendar, ChevronRight, PhoneCall } from "lucide-react";

export default function MemberCareTeamPage() {
  const supabase = createClient();
  const router = useRouter();

  const [selectedStaff, setSelectedStaff] = useState<Record<string, any> | null>(null);
  const [bookingCoachId, setBookingCoachId] = useState<string | null>(null);

  const { data: assignments, isLoading } = useSWR("care-team-assignments", async () => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return [];

    const { data, error } = await supabase
      .from("care_team_assignments")
      .select(`
        id, role, is_primary,
        staff:profiles!care_team_assignments_staff_id_fkey(
          id, full_name, email, role,
          staff_profiles(*)
        )
      `)
      .eq("member_id", user.id)
      .order("is_primary", { ascending: false });

    if (error) {
      console.error(error);
      return [];
    }
    return data || [];
  });

  async function handleBook(bookingData: any) {
    const { data: { user } } = await supabase.auth.getUser();
    const { error, data: newApt } = await supabase.from("appointments").insert({
      member_id: user!.id,
      staff_id: bookingData.staff_id,
      title: bookingData.title,
      session_type: bookingData.session_type,
      scheduled_start: bookingData.scheduled_start,
      scheduled_end: bookingData.scheduled_end,
      status: "Scheduled",
    }).select().single();

    if (!error && newApt) {
      fetch("/api/appointments", { method: "POST", body: JSON.stringify({ action: "booked", appointmentId: newApt.id }) });
    }
    setBookingCoachId(null);
    router.push("/member/sessions");
  }

  function handleMessage(staffId: string) {
    // Navigate to messages page and possibly pre-select the staff via URL query
    router.push(`/member/messages?staffId=${staffId}`);
  }

  return (
    <div className="mx-auto max-w-6xl px-6 py-10" data-testid="member-care-team-page">
      <div className="mb-10 text-center sm:text-left">
        <h1 className="font-display text-4xl font-medium tracking-tight">My Care Team</h1>
        <p className="mt-2 text-muted-foreground max-w-2xl">
          Meet the specialists supporting your longevity journey. Your care team is dedicated to 
          helping you achieve your personal health goals.
        </p>
      </div>

      {isLoading ? (
        <div className="flex h-64 items-center justify-center">
          <p className="text-muted-foreground">Loading your care team...</p>
        </div>
      ) : assignments?.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-20 text-center bg-muted/20 rounded-2xl border border-white/5">
          <div className="w-48 h-48 mb-6 relative opacity-80">
            {/* Placeholder for premium illustration */}
            <div className="absolute inset-0 bg-gradient-to-tr from-[var(--vx-sapphire)]/20 to-[var(--vx-jade)]/20 rounded-full blur-2xl" />
            <div className="w-full h-full bg-white/5 rounded-full border border-white/10 flex items-center justify-center backdrop-blur-sm">
              <PhoneCall className="text-muted-foreground w-12 h-12" />
            </div>
          </div>
          <h3 className="font-display text-2xl font-medium mb-2">Care Team Not Assigned</h3>
          <p className="text-muted-foreground max-w-sm mx-auto mb-6">
            Your care team will appear here once your onboarding has been reviewed by our medical staff.
          </p>
          <a href="mailto:support@vitalityx.example.com" className="btn btn-outline">
            Contact Support
          </a>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {assignments?.map((assignment: any) => {
            const staff = assignment.staff;
            const profile = staff.staff_profiles?.[0] || {};
            const combinedStaff = { ...staff, staff_profiles: profile };

            return (
              <div 
                key={assignment.id} 
                className="vx-card group flex flex-col overflow-hidden transition-all duration-300 hover:shadow-xl hover:shadow-[var(--vx-sapphire)]/5"
              >
                {/* Card Header with Badges */}
                <div className="relative h-24 bg-gradient-to-r from-muted to-muted/50">
                  {assignment.is_primary && (
                    <div className="absolute top-4 right-4 bg-[var(--vx-coral)] text-white text-[10px] font-bold uppercase tracking-wider px-3 py-1 rounded-full shadow-sm">
                      Primary Care Lead
                    </div>
                  )}
                </div>

                <div className="px-6 flex-1 flex flex-col">
                  {/* Avatar */}
                  <div className="-mt-12 mb-4 w-24 h-24 rounded-full border-4 border-card bg-muted overflow-hidden relative shadow-md">
                    {profile.profile_photo ? (
                      <Image 
                        src={profile.profile_photo} 
                        alt={staff.full_name} 
                        fill 
                        className="object-cover"
                      />
                    ) : (
                      <div className="w-full h-full flex items-center justify-center text-2xl font-display bg-[var(--vx-jade)]/10 text-[var(--vx-jade)]">
                        {staff.full_name?.charAt(0) || "?"}
                      </div>
                    )}
                  </div>

                  {/* Info */}
                  <div>
                    <h3 className="font-display text-xl font-medium">{staff.full_name}</h3>
                    <p className="text-sm font-medium text-[var(--vx-sapphire)] mt-0.5">
                      {assignment.role} {profile.credentials ? `• ${profile.credentials}` : ""}
                    </p>
                    {profile.specialization && (
                      <p className="text-xs text-muted-foreground mt-2 line-clamp-1">{profile.specialization}</p>
                    )}
                  </div>

                  {/* Quick details */}
                  <div className="mt-4 flex flex-wrap gap-y-2 gap-x-4 text-xs text-muted-foreground">
                    {profile.years_experience && <span>{profile.years_experience} Yrs Exp</span>}
                    {profile.languages && <span>{profile.languages}</span>}
                  </div>

                  {/* Spacer to push buttons to bottom */}
                  <div className="flex-1 min-h-[1.5rem]" />

                  {/* Actions */}
                  <div className="mt-6 pt-4 border-t border-border flex flex-col gap-2 pb-6">
                    <button 
                      onClick={() => setSelectedStaff(combinedStaff)}
                      className="w-full flex items-center justify-between px-4 py-2.5 text-sm font-medium rounded-xl hover:bg-white/5 transition-colors text-left"
                    >
                      View Full Profile
                      <ChevronRight size={16} className="text-muted-foreground group-hover:text-foreground transition-colors" />
                    </button>

                    <div className="grid grid-cols-2 gap-2 mt-2">
                      <button 
                        onClick={() => profile.accepts_messages ? handleMessage(staff.id) : null}
                        disabled={!profile.accepts_messages}
                        className="btn btn-outline py-2 flex items-center justify-center gap-2 text-xs"
                      >
                        <MessageCircle size={14} /> Message
                      </button>

                      <button 
                        onClick={() => profile.booking_enabled ? setBookingCoachId(staff.id) : null}
                        disabled={!profile.booking_enabled}
                        className="btn btn-primary py-2 flex items-center justify-center gap-2 text-xs"
                      >
                        <Calendar size={14} /> Book
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {selectedStaff && (
        <StaffProfileModal 
          staff={selectedStaff}
          onClose={() => setSelectedStaff(null)}
          onBook={selectedStaff.staff_profiles?.booking_enabled ? () => {
            setSelectedStaff(null);
            setBookingCoachId(selectedStaff.id);
          } : undefined}
          onMessage={selectedStaff.staff_profiles?.accepts_messages ? () => {
            handleMessage(selectedStaff.id);
          } : undefined}
        />
      )}

      {bookingCoachId && (
        <BookingModal 
          preselectedCoachId={bookingCoachId}
          onClose={() => setBookingCoachId(null)}
          onBook={handleBook}
        />
      )}
    </div>
  );
}

"use client";

import { useState } from "react";
import useSWR from "swr";
import { createClient } from "@/lib/supabase/client";
import { Search, Filter, ShieldAlert } from "lucide-react";

export default function StaffAuditPage() {
  const supabase = createClient();
  const [search, setSearch] = useState("");
  const [actionFilter, setActionFilter] = useState("All");

  const { data: logs, isLoading } = useSWR("staff-audit-logs", async () => {
    const { data, error } = await supabase
      .from("audit_logs")
      .select("*, profiles!actor_id(full_name, email)")
      .order("created_at", { ascending: false })
      .limit(200);

    if (error) {
      console.error(error);
      return [];
    }
    return data;
  });

  const actions = Array.from(new Set((logs || []).map((l: any) => l.action)));

  const filteredLogs = (logs || []).filter((log: any) => {
    const matchSearch = 
      log.action.toLowerCase().includes(search.toLowerCase()) ||
      (log.profiles?.full_name || "").toLowerCase().includes(search.toLowerCase()) ||
      (log.profiles?.email || "").toLowerCase().includes(search.toLowerCase());
    const matchAction = actionFilter === "All" || log.action === actionFilter;
    return matchSearch && matchAction;
  });

  return (
    <div className="mx-auto max-w-6xl px-6 py-10" data-testid="staff-audit-page">
      <div className="flex items-center gap-3 mb-2">
        <div className="p-3 bg-[var(--vx-coral)]/10 text-[var(--vx-coral)] rounded-xl">
          <ShieldAlert size={24} />
        </div>
        <div>
          <h1 className="font-display text-4xl font-medium">Audit Logs</h1>
          <p className="mt-1 text-muted-foreground">Immutable compliance and activity tracking.</p>
        </div>
      </div>

      <div className="flex flex-col sm:flex-row gap-4 my-8">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" size={16} />
          <input 
            type="text"
            placeholder="Search by action, name, or email..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="vx-input pl-10 w-full"
          />
        </div>
        <div className="relative w-full sm:w-64">
          <Filter className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" size={16} />
          <select 
            value={actionFilter} 
            onChange={(e) => setActionFilter(e.target.value)}
            className="vx-input pl-10 w-full appearance-none"
          >
            <option value="All">All Actions</option>
            {actions.map((a: any) => (
              <option key={a} value={a}>{a}</option>
            ))}
          </select>
        </div>
      </div>

      <div className="vx-card overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-muted/50 text-muted-foreground">
              <tr>
                <th className="px-4 py-3 font-medium">Timestamp</th>
                <th className="px-4 py-3 font-medium">Actor</th>
                <th className="px-4 py-3 font-medium">Action</th>
                <th className="px-4 py-3 font-medium">Resource</th>
                <th className="px-4 py-3 font-medium">IP Address</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-border">
              {isLoading ? (
                <tr>
                  <td colSpan={5} className="px-4 py-8 text-center text-muted-foreground">Loading audit logs...</td>
                </tr>
              ) : filteredLogs.length === 0 ? (
                <tr>
                  <td colSpan={5} className="px-4 py-8 text-center text-muted-foreground">No logs found.</td>
                </tr>
              ) : (
                filteredLogs.map((log: any) => (
                  <tr key={log.id} className="hover:bg-muted/30 transition-colors group">
                    <td className="px-4 py-3 whitespace-nowrap text-xs text-muted-foreground">
                      {new Date(log.created_at).toLocaleString()}
                    </td>
                    <td className="px-4 py-3">
                      <p className="font-medium">{log.profiles?.full_name || "Unknown User"}</p>
                      <p className="text-xs text-muted-foreground">{log.profiles?.email}</p>
                      <span className="text-[10px] uppercase tracking-wider text-muted-foreground">{log.actor_role}</span>
                    </td>
                    <td className="px-4 py-3">
                      <span className="badge badge-amber">{log.action}</span>
                    </td>
                    <td className="px-4 py-3 text-xs">
                      {log.resource_type ? (
                        <>
                          <span className="font-mono text-muted-foreground">{log.resource_type}</span>
                          <p className="text-[10px] text-muted-foreground truncate w-32" title={log.resource_id}>{log.resource_id}</p>
                        </>
                      ) : (
                        <span className="text-muted-foreground">—</span>
                      )}
                    </td>
                    <td className="px-4 py-3 text-xs font-mono text-muted-foreground">
                      {log.ip_address}
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import useSWR from "swr";
import { createClient } from "@/lib/supabase/client";
import { toast } from "sonner";
import { Search, Plus, Trash2, Shield, User, Loader2 } from "lucide-react";
import { getInitials } from "@/lib/utils";

const ROLES = ['Physician', 'Health Coach', 'Nutritionist', 'Functional Medicine Practitioner', 'Lab Coordinator', 'Customer Success', 'Primary Care Lead'];

export default function StaffCareTeamManagement() {
  const supabase = createClient();
  const [memberSearch, setMemberSearch] = useState("");
  const [staffSearch, setStaffSearch] = useState("");

  // Modals/State
  const [assigningTo, setAssigningTo] = useState<string | null>(null); // Member ID
  const [selectedRole, setSelectedRole] = useState(ROLES[0]);

  // Fetch Members
  const { data: members, isLoading: loadingMembers } = useSWR("care-team-members", async () => {
    const { data } = await supabase
      .from("profiles")
      .select(`
        id, full_name, email,
        care_team_assignments(
          id, role, is_primary,
          staff:profiles!care_team_assignments_staff_id_fkey(id, full_name)
        )
      `)
      .eq("role", "Member")
      .order("created_at", { ascending: false });
    return data || [];
  });

  // Fetch Staff
  const { data: staffList } = useSWR("care-team-staff", async () => {
    const { data } = await supabase
      .from("profiles")
      .select("id, full_name, email, role")
      .in("role", ["Coach", "Admin", "Ops"])
      .order("full_name");
    return data || [];
  });

  const filteredMembers = members?.filter(m => 
    m.full_name?.toLowerCase().includes(memberSearch.toLowerCase()) || 
    m.email?.toLowerCase().includes(memberSearch.toLowerCase())
  ) || [];

  const filteredStaff = staffList?.filter(s =>
    s.full_name?.toLowerCase().includes(staffSearch.toLowerCase())
  ) || [];

  async function handleAssign(staffId: string) {
    if (!assigningTo) return;
    const { error } = await supabase.from("care_team_assignments").insert({
      member_id: assigningTo,
      staff_id: staffId,
      role: selectedRole,
    });

    if (error) {
      if (error.code === '23505') toast.error("Staff member already assigned to this client.");
      else toast.error(error.message);
    } else {
      toast.success("Clinician assigned");
      // Trigger notification for member
      fetch("/api/notifications/trigger", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          userId: assigningTo,
          title: "Care Team Updated",
          message: `A new ${selectedRole} has been assigned to your care team.`,
          type: "care_team_updated",
          category: "team",
          link: "/member/team"
        })
      });
      setAssigningTo(null);
    }
  }

  async function handleRemove(assignmentId: string) {
    const { error } = await supabase.from("care_team_assignments").delete().eq("id", assignmentId);
    if (error) toast.error(error.message);
    else toast.success("Clinician removed");
  }

  async function togglePrimary(assignmentId: string, currentStatus: boolean, memberId: string) {
    // If making primary, first unset primary for others
    if (!currentStatus) {
      await supabase.from("care_team_assignments").update({ is_primary: false }).eq("member_id", memberId);
    }
    const { error } = await supabase.from("care_team_assignments").update({ is_primary: !currentStatus }).eq("id", assignmentId);
    if (error) toast.error(error.message);
    else toast.success("Primary status updated");
  }

  return (
    <div className="mx-auto max-w-6xl px-6 py-10" data-testid="staff-care-team-page">
      <div className="mb-8">
        <h1 className="font-display text-4xl font-medium">Care Team Management</h1>
        <p className="mt-2 text-muted-foreground">Assign clinicians, manage roles, and set primary care leads for members.</p>
      </div>

      <div className="mb-6 relative max-w-md">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" size={16} />
        <input 
          type="text"
          placeholder="Search members..."
          value={memberSearch}
          onChange={(e) => setMemberSearch(e.target.value)}
          className="vx-input pl-10 w-full"
        />
      </div>

      <div className="vx-card overflow-hidden">
        {loadingMembers ? (
          <div className="p-8 flex justify-center"><Loader2 className="animate-spin text-muted-foreground" /></div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-left text-sm">
              <thead className="bg-muted/50 text-muted-foreground border-b border-border">
                <tr>
                  <th className="px-6 py-4 font-medium">Member</th>
                  <th className="px-6 py-4 font-medium w-1/2">Care Team</th>
                  <th className="px-6 py-4 font-medium text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {filteredMembers.map(m => (
                  <tr key={m.id} className="hover:bg-muted/30 transition-colors">
                    <td className="px-6 py-4">
                      <p className="font-medium">{m.full_name}</p>
                      <p className="text-xs text-muted-foreground">{m.email}</p>
                    </td>
                    <td className="px-6 py-4">
                      {m.care_team_assignments?.length === 0 ? (
                        <span className="text-muted-foreground text-xs italic">No team assigned</span>
                      ) : (
                        <div className="flex flex-col gap-2">
                          {m.care_team_assignments.map((a: any) => (
                            <div key={a.id} className="flex items-center justify-between bg-white/5 p-2 rounded-lg border border-white/5">
                              <div className="flex items-center gap-2">
                                <div className="w-6 h-6 rounded-full bg-muted flex items-center justify-center text-[10px] font-bold text-muted-foreground">
                                  {getInitials(a.staff?.full_name)}
                                </div>
                                <div>
                                  <p className="text-xs font-medium">{a.staff?.full_name}</p>
                                  <p className="text-[10px] text-muted-foreground">{a.role}</p>
                                </div>
                              </div>
                              <div className="flex items-center gap-1">
                                <button 
                                  onClick={() => togglePrimary(a.id, a.is_primary, m.id)}
                                  title={a.is_primary ? "Remove Primary" : "Make Primary"}
                                  className={`p-1.5 rounded-md transition-colors ${a.is_primary ? 'text-[var(--vx-coral)] bg-[var(--vx-coral)]/10' : 'text-muted-foreground hover:bg-white/10'}`}
                                >
                                  <Shield size={14} />
                                </button>
                                <button 
                                  onClick={() => handleRemove(a.id)}
                                  className="p-1.5 rounded-md text-muted-foreground hover:text-destructive hover:bg-destructive/10 transition-colors"
                                >
                                  <Trash2 size={14} />
                                </button>
                              </div>
                            </div>
                          ))}
                        </div>
                      )}
                    </td>
                    <td className="px-6 py-4 text-right align-top">
                      <button 
                        onClick={() => setAssigningTo(m.id)}
                        className="btn btn-outline text-xs py-1.5 px-3 flex items-center gap-1 inline-flex"
                      >
                        <Plus size={14} /> Assign
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {assigningTo && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 p-4 backdrop-blur-sm">
          <div className="w-full max-w-md overflow-hidden rounded-2xl bg-card shadow-2xl">
            <div className="p-6 border-b border-border">
              <h2 className="font-display text-xl font-medium">Assign Clinician</h2>
              <p className="text-sm text-muted-foreground">Select a staff member and role.</p>
            </div>

            <div className="p-6 space-y-4">
              <div>
                <label className="text-xs font-medium uppercase tracking-wider text-muted-foreground mb-1.5 block">Search Staff</label>
                <div className="relative">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" size={16} />
                  <input 
                    type="text" 
                    placeholder="Search by name..." 
                    className="vx-input pl-10 w-full"
                    value={staffSearch}
                    onChange={e => setStaffSearch(e.target.value)}
                  />
                </div>
              </div>

              <div>
                <label className="text-xs font-medium uppercase tracking-wider text-muted-foreground mb-1.5 block">Role</label>
                <select 
                  className="vx-input w-full appearance-none"
                  value={selectedRole}
                  onChange={e => setSelectedRole(e.target.value)}
                >
                  {ROLES.map(r => <option key={r} value={r}>{r}</option>)}
                </select>
              </div>

              <div className="max-h-60 overflow-y-auto border border-border rounded-xl divide-y divide-border mt-4">
                {filteredStaff.map(s => (
                  <button 
                    key={s.id}
                    onClick={() => handleAssign(s.id)}
                    className="w-full flex items-center justify-between p-3 hover:bg-muted/50 transition-colors text-left"
                  >
                    <div>
                      <p className="font-medium text-sm">{s.full_name}</p>
                      <p className="text-xs text-muted-foreground">{s.email}</p>
                    </div>
                    <Plus size={16} className="text-muted-foreground" />
                  </button>
                ))}
              </div>
            </div>

            <div className="p-4 border-t border-border flex justify-end">
              <button onClick={() => setAssigningTo(null)} className="btn btn-ghost">Cancel</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { use, useState } from "react";
import useSWR from "swr";
import { createClient } from "@/lib/supabase/client";
import { ClientTabs } from "@/components/staff/client-tabs";
import { DocumentCard } from "@/components/documents/DocumentCard";
import { DocumentUpload } from "@/components/documents/DocumentUpload";
import { Search, Filter, Plus } from "lucide-react";

const CATEGORIES = ["All", "Lab Report", "Genetics Report", "Protocol", "Invoice", "Membership", "Consent", "Medical Form", "Other"];

export default function StaffDocumentsPage({ params }: { params: Promise<{ id: string }> }) {
  const { id } = use(params);
  const supabase = createClient();

  const [activeCategory, setActiveCategory] = useState("All");
  const [search, setSearch] = useState("");
  const [showUpload, setShowUpload] = useState(false);
  const [replaceDoc, setReplaceDoc] = useState<{id: string, path: string} | null>(null);

  const { data: documents, isLoading, mutate } = useSWR(`staff-documents-${id}`, async () => {
    const { data, error } = await supabase
      .from("documents")
      .select("*")
      .eq("member_id", id)
      .order("created_at", { ascending: false });

    if (error) {
      console.error(error);
      return [];
    }
    return data;
  });

  const filteredDocs = (documents || []).filter((doc: Record<string, any>) => {
    const matchesCategory = activeCategory === "All" || doc.category === activeCategory;
    const matchesSearch = doc.title.toLowerCase().includes(search.toLowerCase()) || 
                          doc.file_name.toLowerCase().includes(search.toLowerCase()) ||
                          (doc.description || "").toLowerCase().includes(search.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  return (
    <div className="mx-auto max-w-5xl px-6 py-10" data-testid="staff-documents-page">
      <div className="flex items-center justify-between mb-2">
        <h1 className="font-display text-4xl font-medium">Documents</h1>
        {!showUpload && !replaceDoc && (
          <button onClick={() => setShowUpload(true)} className="btn btn-primary flex items-center gap-2">
            <Plus size={16} /> Upload Document
          </button>
        )}
      </div>

      <ClientTabs id={id} />

      {(showUpload || replaceDoc) && (
        <div className="mb-10 relative">
          <button 
            onClick={() => { setShowUpload(false); setReplaceDoc(null); }} 
            className="absolute -top-3 -right-3 w-8 h-8 flex items-center justify-center bg-card border border-border rounded-full hover:bg-muted z-10"
          >
            ✕
          </button>
          <DocumentUpload 
            memberId={id} 
            onUploadSuccess={() => { setShowUpload(false); setReplaceDoc(null); mutate(); }} 
            replaceDocId={replaceDoc?.id}
            replaceDocPath={replaceDoc?.path}
          />
        </div>
      )}

      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-6">
        <div className="flex items-center gap-2 overflow-x-auto pb-2 scrollbar-hide">
          <Filter size={16} className="text-muted-foreground mr-2 shrink-0" />
          {CATEGORIES.map(cat => (
            <button 
              key={cat}
              onClick={() => setActiveCategory(cat)}
              className={`whitespace-nowrap px-3 py-1.5 rounded-full text-xs transition-colors border ${activeCategory === cat ? "bg-[var(--vx-jade)] text-black border-[var(--vx-jade)] font-medium" : "border-white/10 text-muted-foreground hover:bg-white/5"}`}
            >
              {cat}
            </button>
          ))}
        </div>

        <div className="relative shrink-0">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" size={14} />
          <input 
            type="text" 
            placeholder="Search files..." 
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="vx-input pl-9 w-full sm:w-48 text-sm py-1.5 min-h-0 h-9"
          />
        </div>
      </div>

      {isLoading ? (
        <div className="space-y-4">
          {[1,2,3].map(i => <div key={i} className="h-24 bg-white/5 animate-pulse rounded-2xl" />)}
        </div>
      ) : filteredDocs.length === 0 ? (
        <div className="text-center py-16 bg-white/5 rounded-2xl border border-white/5 border-dashed">
          <p className="text-muted-foreground">No documents found for this client.</p>
        </div>
      ) : (
        <div className="flex flex-col gap-4">
          {filteredDocs.map((doc: Record<string, any>) => (
            <DocumentCard 
              key={doc.id} 
              document={doc} 
              isStaff 
              onDelete={() => mutate()} 
              onReplace={() => { setReplaceDoc({ id: doc.id, path: doc.storage_path }); window.scrollTo({ top: 0, behavior: 'smooth' }); }}
            />
          ))}
        </div>
      )}
    </div>
  );
}

"use client";
import { use, useState } from "react";
import useSWR from "swr";
import { createClient } from "@/lib/supabase/client";
import { toast } from "sonner";
import { ClientTabs } from "@/components/staff/client-tabs";

const supabase = createClient();

export default function LabsPage({ params }: { params: Promise<{ id: string }> }) {
  const { id } = use(params);
  const { data, mutate } = useSWR(`labs-${id}`, async () => {
    const { data: labs } = await supabase.from("lab_results").select("*").eq("member_id", id).order("tested_at", { ascending: false });
    return labs || [];
  });
  const [bioAge, setBioAge] = useState("");
  const [testedAt, setTestedAt] = useState("");
  const [name, setName] = useState("");
  const [value, setValue] = useState("");
  const [unit, setUnit] = useState("");
  const [status, setStatus] = useState<"optimal"|"borderline"|"elevated">("optimal");

  async function uploadLab() {
    const { data: { user } } = await supabase.auth.getUser();
    const { error } = await supabase.from("lab_results").insert({
      member_id: id, biological_age: bioAge ? Number(bioAge) : null, tested_at: testedAt || null,
      uploaded_by: user!.id,
    });
    if (error) return toast.error(error.message);
    toast.success("Lab record saved");
    setBioAge(""); setTestedAt("");
    mutate();
  }

  async function addBiomarker() {
    const { error } = await supabase.from("biomarkers").insert({
      member_id: id, name, value: value ? Number(value) : null, unit, status, tested_at: testedAt || null,
    });
    if (error) return toast.error(error.message);
    toast.success("Biomarker added");

    // Trigger recalculation asynchronously in background
    fetch("/api/bio-age/trigger", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ member_id: id })
    }).catch(e => console.error("Recalculation error:", e));

    setName(""); setValue(""); setUnit("");
  }

  return (
    <div className="mx-auto max-w-3xl px-6 py-10" data-testid="staff-labs-page">
      <h1 className="font-display text-4xl font-medium">Labs</h1>

      <ClientTabs id={id} />

      <div className="mt-6 vx-card p-5 space-y-3">
        <p className="font-medium">Record biological age</p>
        <p className="text-xs text-muted-foreground mb-2">Note: To upload the actual Lab Report PDF, please use the <a href={`/staff/clients/${id}/documents`} className="underline text-[var(--vx-jade)]">Documents tab</a>.</p>
        <input data-testid="lab-tested-at" type="date" value={testedAt} onChange={(e) => setTestedAt(e.target.value)} className="vx-input" />
        <input data-testid="lab-bio-age" type="number" step="0.1" value={bioAge} onChange={(e) => setBioAge(e.target.value)} placeholder="Biological age (yrs)" className="vx-input" />
        <button data-testid="lab-upload" onClick={uploadLab} className="btn btn-primary">Save record</button>
      </div>

      <div className="mt-6 vx-card p-5 space-y-3">
        <p className="font-medium">Add biomarker manually</p>
        <input data-testid="bm-name" value={name} onChange={(e) => setName(e.target.value)} placeholder="Marker name (e.g. ApoB)" className="vx-input" />
        <div className="flex gap-2">
          <input data-testid="bm-value" value={value} onChange={(e) => setValue(e.target.value)} placeholder="Value" className="vx-input flex-1" />
          <input data-testid="bm-unit" value={unit} onChange={(e) => setUnit(e.target.value)} placeholder="Unit (mg/dL)" className="vx-input flex-1" />
        </div>
        <select data-testid="bm-status" value={status} onChange={(e) => setStatus(e.target.value as any)} className="vx-input">
          <option value="optimal">Optimal</option><option value="borderline">Borderline</option><option value="elevated">Elevated</option>
        </select>
        <button data-testid="bm-add" onClick={addBiomarker} className="btn btn-outline">Add biomarker</button>
      </div>

      <h2 className="mt-10 font-display text-xl">Recent labs</h2>
      <ul className="mt-3 space-y-2">
        {data?.map((l: any) => (
          <li key={l.id} className="vx-card p-3 text-sm flex justify-between">
            <span>Tested {l.tested_at} · Bio age {l.biological_age ?? "—"}</span>
          </li>
        ))}
      </ul>
    </div>
  );
}

"use client";
import React, { useEffect, useState, useRef } from "react";
import { createClient } from "@/lib/supabase/client";
import { ClientTabs } from "@/components/staff/client-tabs";
import { getInitials } from "@/lib/utils";
import { toast } from "sonner";

const supabase = createClient();
type Msg = { id: string; sender_id: string; receiver_id: string; content: string; created_at: string };

export default function ClientMessagesPage({ params }: { params: Promise<{ id: string }> }) {
  const { id: memberId } = React.use(params);
  const [me, setMe] = useState<string | null>(null);
  const [clientProfile, setClientProfile] = useState<any | null>(null);
  const [assignedCoachId, setAssignedCoachId] = useState<string | null>(null);
  const [partners, setPartners] = useState<any[]>([]);
  const [selectedPartner, setSelectedPartner] = useState<any | null>(null);
  const [messages, setMessages] = useState<Msg[]>([]);
  const [text, setText] = useState("");
  const [lastReadTimestamps, setLastReadTimestamps] = useState<Record<string, string>>({});
  const endRef = useRef<HTMLDivElement>(null);

  const loadAll = React.useCallback(async () => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;
    setMe(user.id);

    // Fetch client profile
    const { data: clientP } = await supabase
      .from("profiles")
      .select("id, full_name, email")
      .eq("id", memberId)
      .single();
    setClientProfile(clientP);

    // Fetch assigned coach
    const { data: cr } = await supabase
      .from("client_records")
      .select("assigned_coach_id")
      .eq("member_id", memberId)
      .single();
    const coachId = cr?.assigned_coach_id || null;
    setAssignedCoachId(coachId);

    // Fetch all messages involving the client
    const { data: allMsgs } = await supabase
      .from("messages")
      .select("*")
      .or(`sender_id.eq.${memberId},receiver_id.eq.${memberId}`)
      .order("created_at");

    const msgs = allMsgs || [];
    setMessages(msgs);

    // Identify all staff partners who have messaged client or are assigned to client
    const partnerIds = new Set<string>();
    if (coachId) partnerIds.add(coachId);
    partnerIds.add(user.id); // Always include current logged-in staff member
    msgs.forEach((m) => {
      if (m.sender_id !== memberId) partnerIds.add(m.sender_id);
      if (m.receiver_id !== memberId) partnerIds.add(m.receiver_id);
    });

    if (partnerIds.size > 0) {
      const { data: profiles } = await supabase
        .from("profiles")
        .select("id, full_name, role, email")
        .in("id", Array.from(partnerIds));

      const loadedPartners = profiles || [];
      setPartners(loadedPartners);

      // Default to opening assigned coach thread on load (or first, preserving selection)
      setSelectedPartner((current: any) => {
        if (current) {
          const updated = loadedPartners.find((p) => p.id === current.id);
          return updated || current;
        }
        if (coachId) {
          return loadedPartners.find((p) => p.id === coachId) || loadedPartners[0] || null;
        }
        return loadedPartners.find((p) => p.id === user.id) || loadedPartners[0] || null;
      });
    }
  }, [memberId]);

  useEffect(() => {
    Promise.resolve().then(() => {
      const saved = localStorage.getItem(`vx_staff_${memberId}_last_read_timestamps`);
      if (saved) {
        try {
          setLastReadTimestamps(JSON.parse(saved));
        } catch (e) {
          console.warn(e);
        }
      }
    });
  }, [memberId]);

  useEffect(() => {
    Promise.resolve().then(() => {
      loadAll();
    });

    const channel = supabase.channel(`messages-staff-${memberId}`)
      .on("postgres_changes", { event: "INSERT", schema: "public", table: "messages" }, (payload) => {
        const m = payload.new as Msg;
        if (m.sender_id === memberId || m.receiver_id === memberId) {
          setMessages((prev) => {
            if (prev.find((x) => x.id === m.id)) return prev;
            return [...prev, m];
          });
          loadAll();
        }
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [memberId, loadAll]);

  useEffect(() => {
    if (selectedPartner) {
      Promise.resolve().then(() => {
        const nowStr = new Date().toISOString();
        setLastReadTimestamps((prev) => {
          const next = { ...prev, [selectedPartner.id]: nowStr };
          localStorage.setItem(`vx_staff_${memberId}_last_read_timestamps`, JSON.stringify(next));
          return next;
        });
      });
    }
  }, [selectedPartner, messages, memberId]);

  useEffect(() => {
    endRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, selectedPartner]);

  async function send() {
    if (!text.trim() || !me || !selectedPartner || selectedPartner.id !== me) return;
    const { error, data } = await supabase.from("messages").insert({
      sender_id: me,
      receiver_id: memberId,
      content: text.trim()
    }).select().single();
    if (error) return toast.error(error.message);
    setText("");
    if (data) {
      setMessages((prev) => prev.find((x) => x.id === data.id) ? prev : [...prev, data as Msg]);
    }
  }

  // Map partners with details
  const enrichedPartners = partners.map((p) => {
    const thread = messages.filter(
      (m) =>
        (m.sender_id === memberId && m.receiver_id === p.id) ||
        (m.sender_id === p.id && m.receiver_id === memberId)
    );
    const lastMsg = thread[thread.length - 1];
    const lastRead = lastReadTimestamps[p.id] || "1970-01-01T00:00:00.000Z";
    const unreadCount = thread.filter(
      (m) =>
        m.sender_id === memberId &&
        new Date(m.created_at) > new Date(lastRead)
    ).length;

    return {
      ...p,
      lastMessageContent: lastMsg ? lastMsg.content : "No messages yet",
      unreadCount,
    };
  });

  const selectedThreadMessages = selectedPartner
    ? messages.filter(
        (m) =>
          (m.sender_id === memberId && m.receiver_id === selectedPartner.id) ||
          (m.sender_id === selectedPartner.id && m.receiver_id === memberId)
      )
    : [];

  const isMyThread = selectedPartner?.id === me;

  return (
    <div className="mx-auto flex h-[calc(100vh-4rem)] max-w-5xl gap-6 px-6 py-6" data-testid="staff-client-messages-page">
      {/* Left panel: thread list */}
      <div className="w-80 shrink-0 border-r border-border pr-4 flex flex-col h-full overflow-y-auto">
        <div className="mb-4">
          <ClientTabs id={memberId} />
        </div>
        <div className="space-y-1.5 flex-1">
          {enrichedPartners.map((p) => {
            const isActive = selectedPartner?.id === p.id;
            const isSelf = p.id === me;
            return (
              <button
                key={p.id}
                onClick={() => setSelectedPartner(p)}
                className={`w-full flex items-center gap-3 rounded-xl p-3 text-left transition border ${
                  isActive ? "bg-muted border-border" : "hover:bg-muted/50 border-transparent"
                }`}
              >
                <span className="flex h-10 w-10 shrink-0 items-center justify-center rounded-full bg-[var(--vx-ink)] text-sm font-semibold text-white">
                  {getInitials(p.full_name || p.email)}
                </span>
                <div className="min-w-0 flex-1">
                  <div className="flex justify-between items-baseline">
                    <p className="font-medium text-sm truncate">
                      {p.full_name || "Staff"} {isSelf && "(You)"}
                    </p>
                    <span className="text-[10px] text-muted-foreground uppercase tracking-wider">{p.role}</span>
                  </div>
                  <p className="text-xs text-muted-foreground truncate mt-0.5">{p.lastMessageContent}</p>
                </div>
                {p.unreadCount > 0 && (
                  <span className="flex h-5 min-w-[20px] items-center justify-center rounded-full bg-destructive px-1 text-[10px] font-semibold text-white shrink-0">
                    {p.unreadCount}
                  </span>
                )}
              </button>
            );
          })}
        </div>
      </div>

      {/* Right panel: current thread */}
      <div className="flex-1 flex flex-col h-full">
        {selectedPartner ? (
          <>
            <div className="border-b border-border pb-4 flex justify-between items-center">
              <div>
                <h1 className="font-display text-2xl">
                  {selectedPartner.full_name || "Staff"} {isMyThread && "(You)"}
                </h1>
                <p className="text-xs text-muted-foreground uppercase tracking-wider mt-0.5">
                  Thread with {clientProfile?.full_name || "Client"}
                </p>
              </div>
            </div>
            {/* Messages list */}
            <div className="flex-1 overflow-y-auto py-4 space-y-2" data-testid="messages-list">
              {selectedThreadMessages.length === 0 ? (
                <p className="text-center text-sm text-muted-foreground py-8">No messages yet. Say hi 👋</p>
              ) : (
                selectedThreadMessages.map((m) => {
                  const isMe = m.sender_id === me;
                  const isClient = m.sender_id === memberId;
                  const senderName = isClient
                    ? clientProfile?.full_name || "Client"
                    : selectedPartner.full_name || "Staff";

                  return (
                    <div key={m.id} className={`flex flex-col ${isMe ? "items-end" : "items-start"}`}>
                      <span className="text-[10px] text-muted-foreground px-2 mb-0.5">
                        {isMe ? "You" : senderName}
                      </span>
                      <div className={`max-w-[75%] rounded-2xl px-4 py-2 text-sm ${isMe ? "bg-[var(--vx-ink)] text-white" : "bg-card border border-border"}`}>
                        {m.content}
                      </div>
                    </div>
                  );
                })
              )}
              <div ref={endRef} />
            </div>
            {/* Input box */}
            <div className="flex flex-col gap-2 border-t border-border pt-4">
              {isMyThread ? (
                <div className="flex gap-2">
                  <input
                    data-testid="message-input"
                    value={text}
                    onChange={(e) => setText(e.target.value)}
                    onKeyDown={(e) => e.key === "Enter" && send()}
                    placeholder="Type a message…"
                    className="vx-input flex-1"
                  />
                  <button data-testid="message-send" onClick={send} className="btn btn-primary">Send</button>
                </div>
              ) : (
                <div className="text-center py-2 px-3 bg-muted/40 rounded-lg border border-border text-xs text-muted-foreground">
                  Viewing history between client and {selectedPartner.full_name}. Switch to your own thread to message this client.
                </div>
              )}
            </div>
          </>
        ) : (
          <div className="flex-1 flex items-center justify-center text-muted-foreground text-sm">
            Select a conversation thread to start viewing
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { use, useState } from "react";
import useSWR from "swr";
import { createClient } from "@/lib/supabase/client";
import { toast } from "sonner";
import { ClientTabs } from "@/components/staff/client-tabs";
import { Lock, Trash2, Plus } from "lucide-react";
import { logClientAudit } from "@/lib/audit-client";

const supabase = createClient();

export default function NotesDocsPage({ params }: { params: Promise<{ id: string }> }) {
  const { id } = use(params);

  // Using SWR to load client record (where we will store the notes in a private_notes JSON array)
  const { data: record, mutate } = useSWR(`client-notes-${id}`, async () => {
    const { data } = await supabase.from("client_records").select("*").eq("member_id", id).single();
    return data;
  });

  const [newNote, setNewNote] = useState("");
  const [addingNote, setAddingNote] = useState(false);

  const privateNotes = record?.intake?.private_notes || [];

  async function addNote() {
    if (!newNote.trim()) return;
    setAddingNote(true);

    const { data: { user } } = await supabase.auth.getUser();

    const note = {
      id: crypto.randomUUID(),
      content: newNote,
      author: user?.id,
      created_at: new Date().toISOString()
    };

    const currentIntake = record?.intake || {};
    const updatedNotes = [note, ...privateNotes];

    const { error } = await supabase.from("client_records").update({
      intake: {
        ...currentIntake,
        private_notes: updatedNotes
      }
    }).eq("member_id", id);

    setAddingNote(false);
    if (error) return toast.error(error.message);

    await logClientAudit("Note created", {
      targetUserId: id,
      resourceType: "note",
      resourceId: note.id,
      metadata: { length: newNote.length }
    });

    toast.success("Note added");
    setNewNote("");
    mutate();
  }

  async function deleteNote(noteId: string) {
    const currentIntake = record?.intake || {};
    const updatedNotes = privateNotes.filter((n: any) => n.id !== noteId);

    const { error } = await supabase.from("client_records").update({
      intake: {
        ...currentIntake,
        private_notes: updatedNotes
      }
    }).eq("member_id", id);

    if (error) return toast.error(error.message);

    await logClientAudit("Note updated", {
      targetUserId: id,
      resourceType: "note",
      resourceId: noteId,
      metadata: { status: "deleted" }
    });

    mutate();
  }

  return (
    <div className="mx-auto max-w-5xl px-6 py-10" data-testid="staff-client-notes">
      <h1 className="font-display text-4xl font-medium">Notes</h1>
      <ClientTabs id={id} />

      <div className="grid md:grid-cols-2 gap-10 mt-8">

        {/* Private Notes */}
        <div>
          <div className="flex items-center gap-2 mb-6">
            <h2 className="font-display text-xl">Private Staff Notes</h2>
            <span className="badge badge-amber flex items-center gap-1"><Lock size={12} /> Internal Only</span>
          </div>

          <div className="vx-card p-5 mb-6">
            <textarea 
              value={newNote}
              onChange={(e) => setNewNote(e.target.value)}
              placeholder="Add a clinical observation or operational note..."
              className="vx-input min-h-[100px] mb-3"
            />
            <button onClick={addNote} disabled={addingNote || !newNote.trim()} className="btn btn-primary w-full flex justify-center items-center gap-2">
              <Plus size={16} /> {addingNote ? "Saving..." : "Add Note"}
            </button>
          </div>

          <div className="space-y-4">
            {privateNotes.map((note: any) => (
              <div key={note.id} className="vx-card p-4 bg-muted/20 border-l-4 border-l-amber-500">
                <div className="flex justify-between items-start mb-2">
                  <span className="text-xs font-mono text-muted-foreground">{new Date(note.created_at).toLocaleString()}</span>
                  <button onClick={() => deleteNote(note.id)} className="text-muted-foreground hover:text-red-500 transition"><Trash2 size={14} /></button>
                </div>
                <p className="text-sm whitespace-pre-wrap">{note.content}</p>
              </div>
            ))}
            {privateNotes.length === 0 && <p className="text-sm text-muted-foreground">No notes yet.</p>}
          </div>
        </div>

      </div>
    </div>
  );
}

import { createClient } from "@/lib/supabase/server";
