function Card({ title, children }: { title: string; children: React.ReactNode }) {
  return <div className="vx-card p-5"><p className="text-xs uppercase tracking-widest text-muted-foreground">{title}</p><div className="mt-3">{children}</div></div>;
}

"use client";
import { use, useEffect, useState } from "react";
import useSWR from "swr";
import { createClient } from "@/lib/supabase/client";
import { toast } from "sonner";
import { Trash2 } from "lucide-react";
import { ClientTabs } from "@/components/staff/client-tabs";
import { logClientAudit } from "@/lib/audit-client";

const supabase = createClient();

export default function ProtocolBuilder({ params }: { params: Promise<{ id: string }> }) {
  const { id } = use(params);
  const { data, mutate } = useSWR(`builder-${id}`, async () => {
    const { data } = await supabase.from("protocol_items").select("*").eq("member_id", id).order("created_at");
    return data || [];
  });
  const [title, setTitle] = useState("");
  const [why, setWhy] = useState("");

  async function add() {
    if (!title.trim()) return;
    const { data: { user } } = await supabase.auth.getUser();
    const { error } = await supabase.from("protocol_items").insert({ member_id: id, title, why_text: why, created_by: user!.id });
    if (error) return toast.error(error.message);

    await logClientAudit("Protocol created", {
      targetUserId: id,
      resourceType: "protocol",
      metadata: { title }
    });

    setTitle(""); setWhy(""); mutate();
  }
  async function remove(itemId: string) {
    const { error } = await supabase.from("protocol_items").update({ active: false }).eq("id", itemId);
    if (error) return toast.error(error.message);

    await logClientAudit("Protocol updated", {
      targetUserId: id,
      resourceType: "protocol",
      resourceId: itemId,
      metadata: { status: "removed" }
    });

    mutate();
  }

  return (
    <div className="mx-auto max-w-3xl px-6 py-10" data-testid="staff-protocol-builder">
      <h1 className="font-display text-4xl font-medium">Protocol builder</h1>

      <ClientTabs id={id} />
      <div className="mt-6 vx-card p-5 space-y-3">
        <input data-testid="builder-title" value={title} onChange={(e) => setTitle(e.target.value)} placeholder="Item title (e.g. Zone 2 cardio 45 min, 3×/week)" className="vx-input" />
        <textarea data-testid="builder-why" value={why} onChange={(e) => setWhy(e.target.value)} rows={3} placeholder="Why this is in the plan…" className="vx-input" />
        <button data-testid="builder-add" onClick={add} className="btn btn-primary">Add item</button>
      </div>
      <ul className="mt-6 space-y-2">
        {(data || []).filter((i: any) => i.active).map((it: any) => (
          <li key={it.id} className="vx-card flex items-center justify-between p-4">
            <div><p className="font-medium">{it.title}</p>{it.why_text && <p className="mt-1 text-xs text-muted-foreground">{it.why_text}</p>}</div>
            <button data-testid={`builder-remove-${it.id}`} onClick={() => remove(it.id)} className="rounded-full p-2 text-destructive hover:bg-destructive/10"><Trash2 size={16} /></button>
          </li>
        ))}
      </ul>
    </div>
  );
}

import { createClient } from "@/lib/supabase/server";
import { createAdminClient } from "@/lib/supabase/admin";
import { notFound } from "next/navigation";
import { ClientTabs } from "@/components/staff/client-tabs";
import { Activity, FileText, Upload, CheckCircle2 } from "lucide-react";

export default async function TimelinePage({ params }: { params: Promise<{ id: string }> }) {
  const { id } = await params;
  const supabase = await createClient();
  const admin = createAdminClient();

  const { data: profile } = await supabase.from("profiles").select("*").eq("id", id).single();
  if (!profile) notFound();

  // Fetch various records to build a unified timeline
  const [{ data: logs }, { data: labs }] = await Promise.all([
    admin.from("staff_access_logs").select("*").eq("member_id", id).order("created_at", { ascending: false }).limit(20),
    supabase.from("lab_results").select("*").eq("member_id", id).order("created_at", { ascending: false }).limit(5),
  ]);

  // Combine and sort events
  const events = [];

  // 1. Staff access logs
  if (logs) {
    for (const log of logs) {
      events.push({
        id: `log-${log.id}`,
        type: "access",
        title: "Staff Access",
        description: `Staff member (${log.staff_id.substring(0,6)}) accessed ${log.resource_type}`,
        date: new Date(log.created_at),
        icon: <Activity size={16} className="text-blue-500" />
      });
    }
  }

  // 2. Lab uploads
  if (labs) {
    for (const lab of labs) {
      events.push({
        id: `lab-${lab.id}`,
        type: "lab",
        title: "Lab Result Uploaded",
        description: `Biological Age: ${lab.biological_age || "N/A"}. Tested on ${lab.tested_at}`,
        date: new Date(lab.created_at),
        icon: <Upload size={16} className="text-amber-500" />
      });
    }
  }

  // 3. Account creation (mocked based on profile)
  if (profile.created_at) {
    events.push({
      id: "account-created",
      type: "system",
      title: "Account Created",
      description: "Member completed signup flow.",
      date: new Date(profile.created_at),
      icon: <CheckCircle2 size={16} className="text-[var(--vx-jade)]" />
    });
  }

  // Sort descending
  events.sort((a, b) => b.date.getTime() - a.date.getTime());

  return (
    <div className="mx-auto max-w-5xl px-6 py-10" data-testid="staff-client-timeline">
      <h1 className="font-display text-4xl font-medium">{profile.full_name}</h1>
      <ClientTabs id={id} />

      <div className="mt-8 max-w-3xl">
        <h2 className="font-display text-xl mb-6">Audit Log & Timeline</h2>

        <div className="relative border-l border-border pl-6 space-y-8">
          {events.map((e) => (
            <div key={e.id} className="relative">
              <div className="absolute -left-[35px] bg-card p-1 rounded-full border border-border flex items-center justify-center">
                {e.icon}
              </div>
              <div className="vx-card p-4">
                <div className="flex justify-between items-start mb-1">
                  <h3 className="font-medium text-sm">{e.title}</h3>
                  <span className="text-xs text-muted-foreground">{e.date.toLocaleString()}</span>
                </div>
                <p className="text-sm text-muted-foreground">{e.description}</p>
              </div>
            </div>
          ))}

          {events.length === 0 && (
            <p className="text-sm text-muted-foreground">No timeline events found.</p>
          )}
        </div>
      </div>
    </div>
  );
}

