import { useState, useEffect } from "react";
import { format } from "date-fns";
import { createClient } from "@/lib/supabase/client";

const supabase = createClient();

const SESSION_TYPES = [
  "Initial Consultation",
  "Protocol Review",
  "Lab Review",
  "Follow-up",
  "Nutrition Consultation",
  "Lifestyle Coaching",
];

const AVAILABLE_TIMES = [
  "09:00", "10:00", "11:00", "13:00", "14:00", "15:00", "16:00"
];

export function BookingModal({
  onClose,
  onBook,
  preselectedCoachId,
}: {
  onClose: () => void;
  onBook: (data: any) => Promise<void>;
  preselectedCoachId?: string | null;
}) {
  const [step, setStep] = useState(1);
  const [sessionType, setSessionType] = useState(SESSION_TYPES[0]);
  const [coachId, setCoachId] = useState(preselectedCoachId || "");
  const [coaches, setCoaches] = useState<any[]>([]);
  const [date, setDate] = useState("");
  const [time, setTime] = useState("");
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    async function loadCoaches() {
      const { data } = await supabase.from("profiles").select("id, full_name").eq("role", "Coach");
      if (data) setCoaches(data);
      if (!coachId && data && data.length > 0) setCoachId(data[0].id);
    }
    loadCoaches();
  }, [coachId]);

  const handleConfirm = async () => {
    setLoading(true);
    const scheduledStart = new Date(`${date}T${time}:00`).toISOString();
    const scheduledEnd = new Date(new Date(scheduledStart).getTime() + 60 * 60 * 1000).toISOString(); // 1 hour duration

    await onBook({
      title: sessionType,
      session_type: sessionType,
      staff_id: coachId,
      scheduled_start: scheduledStart,
      scheduled_end: scheduledEnd,
    });
    setLoading(false);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 p-4 backdrop-blur-sm transition-opacity">
      <div className="w-full max-w-md overflow-hidden rounded-2xl bg-card shadow-2xl">
        <div className="border-b border-white/5 p-6 pb-4">
          <h2 className="font-display text-2xl font-medium">Book a Session</h2>
          <p className="mt-1 text-sm text-muted-foreground">Step {step} of 3</p>
        </div>

        <div className="p-6">
          {step === 1 && (
            <div className="space-y-4 animate-in fade-in slide-in-from-right-4">
              <div>
                <label className="mb-2 block text-sm font-medium">Session Type</label>
                <select
                  value={sessionType}
                  onChange={(e) => setSessionType(e.target.value)}
                  className="vx-input w-full"
                >
                  {SESSION_TYPES.map((t) => (
                    <option key={t} value={t}>{t}</option>
                  ))}
                </select>
              </div>

              <div>
                <label className="mb-2 block text-sm font-medium">Select Coach</label>
                <select
                  value={coachId}
                  onChange={(e) => setCoachId(e.target.value)}
                  className="vx-input w-full"
                >
                  {coaches.map((c) => (
                    <option key={c.id} value={c.id}>{c.full_name}</option>
                  ))}
                </select>
              </div>

              <div className="mt-6 flex justify-end gap-3 pt-4">
                <button onClick={onClose} className="btn btn-ghost">Cancel</button>
                <button onClick={() => setStep(2)} className="btn btn-primary">Next</button>
              </div>
            </div>
          )}

          {step === 2 && (
            <div className="space-y-4 animate-in fade-in slide-in-from-right-4">
              <div>
                <label className="mb-2 block text-sm font-medium">Select Date</label>
                <input
                  type="date"
                  value={date}
                  onChange={(e) => { setDate(e.target.value); setTime(""); }}
                  className="vx-input w-full"
                  min={new Date().toISOString().split("T")[0]}
                />
              </div>

              {date && (
                <div>
                  <label className="mb-2 block text-sm font-medium">Available Times</label>
                  <div className="grid grid-cols-3 gap-2">
                    {AVAILABLE_TIMES.map((t) => (
                      <button
                        key={t}
                        onClick={() => setTime(t)}
                        className={`rounded-lg border px-3 py-2 text-sm transition-colors ${
                          time === t
                            ? "border-[var(--vx-jade)] bg-[var(--vx-jade)]/10 text-[var(--vx-jade)]"
                            : "border-white/10 hover:border-white/20 hover:bg-white/5"
                        }`}
                      >
                        {t}
                      </button>
                    ))}
                  </div>
                </div>
              )}

              <div className="mt-6 flex justify-between pt-4">
                <button onClick={() => setStep(1)} className="btn btn-ghost">Back</button>
                <button
                  disabled={!date || !time}
                  onClick={() => setStep(3)}
                  className="btn btn-primary"
                >
                  Review
                </button>
              </div>
            </div>
          )}

          {step === 3 && (
            <div className="space-y-4 animate-in fade-in slide-in-from-right-4">
              <div className="rounded-xl bg-white/5 p-4 text-sm">
                <div className="grid grid-cols-3 gap-y-3">
                  <span className="text-muted-foreground">Type</span>
                  <span className="col-span-2 font-medium">{sessionType}</span>

                  <span className="text-muted-foreground">Coach</span>
                  <span className="col-span-2 font-medium">{coaches.find(c => c.id === coachId)?.full_name || "Assigned Coach"}</span>

                  <span className="text-muted-foreground">Date</span>
                  <span className="col-span-2 font-medium">{date && format(new Date(date), "MMMM d, yyyy")}</span>

                  <span className="text-muted-foreground">Time</span>
                  <span className="col-span-2 font-medium">{time}</span>

                  <span className="text-muted-foreground">Duration</span>
                  <span className="col-span-2 font-medium">60 minutes</span>
                </div>
              </div>

              <div className="mt-6 flex justify-between pt-4">
                <button onClick={() => setStep(2)} className="btn btn-ghost" disabled={loading}>Back</button>
                <button
                  onClick={handleConfirm}
                  disabled={loading}
                  className="btn btn-primary flex items-center gap-2"
                >
                  {loading ? "Confirming..." : "Confirm Booking"}
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { createClient } from "@/lib/supabase/client";
import { formatDistanceToNow, format } from "date-fns";
import { Bell, AlertCircle, Calendar, MessageSquare, CheckCircle2, FlaskConical, FileText, UserPlus, FileSignature, Check } from "lucide-react";
import Link from "next/link";
import { useRouter } from "next/navigation";

type Notification = {
  id: string;
  user_id: string;
  title: string;
  message: string;
  type: string;
  category: string;
  link: string | null;
  is_read: boolean;
  created_at: string;
};

export function NotificationHistory() {
  const supabase = createClient();
  const router = useRouter();
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState<"all" | "unread">("all");

  const fetchNotifications = React.useCallback(async () => {
    setLoading(true);
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;

    let query = supabase.from("notifications").select("*").eq("user_id", user.id).order("created_at", { ascending: false });

    if (filter === "unread") {
      query = query.eq("is_read", false);
    }

    const { data, error } = await query;
    if (!error && data) {
      setNotifications(data as Notification[]);
    }
    setLoading(false);
  }, [filter, supabase]);

  useEffect(() => {
    Promise.resolve().then(() => {
      fetchNotifications();
    });
  }, [fetchNotifications]);

  const markAllRead = async () => {
    setNotifications(notifications.map(n => ({ ...n, is_read: true })));
    await fetch("/api/notifications/read", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ action: "mark_all" }),
    });
  };

  const handleNotificationClick = async (n: Notification) => {
    if (!n.is_read) {
      setNotifications(notifications.map(notif => notif.id === n.id ? { ...notif, is_read: true } : notif));
      await fetch("/api/notifications/read", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ action: "mark_one", notificationId: n.id }),
      });
    }
    if (n.link) {
      router.push(n.link);
    }
  };

  const getIcon = (type: string) => {
    if (type.includes("appointment")) return <Calendar size={20} className="text-amber-500" />;
    if (type.includes("message")) return <MessageSquare size={20} className="text-blue-500" />;
    if (type.includes("lab")) return <FlaskConical size={20} className="text-purple-500" />;
    if (type.includes("document")) return <FileText size={20} className="text-gray-500" />;
    if (type.includes("consent")) return <FileSignature size={20} className="text-red-500" />;
    if (type.includes("care_team")) return <UserPlus size={20} className="text-[var(--vx-jade)]" />;
    if (type.includes("success") || type.includes("payment") || type.includes("renewed")) return <CheckCircle2 size={20} className="text-[var(--vx-jade)]" />;
    return <AlertCircle size={20} className="text-[var(--vx-coral)]" />;
  };

  // Group notifications by date
  const grouped = notifications.reduce((acc, notif) => {
    const dateStr = format(new Date(notif.created_at), 'MMMM d, yyyy');
    if (!acc[dateStr]) acc[dateStr] = [];
    acc[dateStr].push(notif);
    return acc;
  }, {} as Record<string, Notification[]>);

  return (
    <div className="mx-auto max-w-4xl px-6 py-10" data-testid="notification-history">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-8">
        <div>
          <h1 className="font-display text-4xl font-medium tracking-tight">Notifications</h1>
          <p className="mt-2 text-muted-foreground">View your recent alerts, messages, and updates.</p>
        </div>

        <div className="flex items-center gap-2">
          <button 
            onClick={markAllRead} 
            className="btn btn-outline text-xs h-9 flex items-center gap-2"
            disabled={notifications.filter(n => !n.is_read).length === 0}
          >
            <Check size={14} /> Mark all read
          </button>
        </div>
      </div>

      <div className="flex border-b border-border mb-6">
        <button 
          onClick={() => setFilter("all")} 
